    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    repairDailyLog,
    commitOnboarding,
    getWeekParams
} from '../lib/firestore';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  repairDay: (date: string, checks: Record<string, boolean>) => Promise<void>;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  dataYear: new Date().getFullYear(),
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [repairTokens, setRepairTokens] = useState<number>(3);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const currentYear = new Date().getFullYear().toString();
    const today = new Date();
    const { year: currentWeekYear, weekId: currentWeekId } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs (Year-based + Week Transformation)
    // We listen to the current year collection.
    // If the current week actually falls in the previous year (e.g. Dec 31 start), we might miss it.
    // So we primarily listen to `currentYear`.
    // And if `currentWeekYear` != `currentYear`, we listen to that specific doc too.

    const yearCollection = collection(db, `users/${userId}/${currentYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];
        let currentRepairTokens = 3;

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // Check if this is the current week for repair tokens
            if (weekId === currentWeekId && currentYear === currentWeekYear) {
                currentRepairTokens = typeof data.repairsLeft === 'number' ? data.repairsLeft : 3;
            }

            // Transform day arrays to DailyLog
            // We need to calculate dates from weekId. 
            // weekId format: "weekN"
            const weekNum = parseInt(weekId.replace('week', ''));
            // Estimate start date. 
            // Week 1 starts on first Sunday of year.
            const yearDate = new Date(parseInt(currentYear), 0, 1);
            while(yearDate.getDay() !== 0) yearDate.setDate(yearDate.getDate() + 1);

            // Add weeks
            yearDate.setDate(yearDate.getDate() + (weekNum - 1) * 7);
            const weekStartMs = yearDate.getTime();

            const days = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];

            days.forEach((dayName, idx) => {
                 const habitIds = data[dayName];
                 if (Array.isArray(habitIds) && habitIds.length > 0) {
                     const logDate = new Date(weekStartMs + (idx * 86400000));
                     // Formatting
                     const y = logDate.getFullYear();
                     const m = String(logDate.getMonth() + 1).padStart(2, '0');
                     const d = String(logDate.getDate()).padStart(2, '0');
                     const dateStr = `${y}-${m}-${d}`;

                     const checks: Record<string, boolean> = {};
                     habitIds.forEach((hid: string) => checks[hid] = true);

                     allLogs.push({
                         date: dateStr,
                         weekId: weekId,
                         checks
                     });
                 }
            });
        });

        setLogs(prev => {
            // Merge? No, just replace for this year context. 
            // In a real app we might merge if we had multiple listeners.
            return allLogs; 
        });

        // Only set repair tokens if we found the current week. 
        // If not found (new week not created yet), it defaults to 3 in UI logic usually, but here we set it.
        // If the doc doesn't exist in snapshot, it means no data logged yet for this week.
        const hasCurrentWeek = snapshot.docs.some(d => d.id === currentWeekId);
        if (!hasCurrentWeek && currentYear === currentWeekYear) {
             setRepairTokens(3);
        } else if (hasCurrentWeek && currentYear === currentWeekYear) {
             setRepairTokens(currentRepairTokens);
        }
    });

    // B2. Edge Case: If current week is in a different year (e.g. late Dec/early Jan transition handled by Sunday logic)
    // For MVP simplicity, we assume user is mostly viewing current year. 
    // If strict overlap support is needed, we would add a listener for `doc(db, users, uid, currentWeekYear, currentWeekId)`.

    // C. User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      await toggleHabitCompletion(user.uid, habitId, date);
  };

  const repairDay = async (date: string, checks: Record<string, boolean>) => {
      if (!user) return;
      await repairDailyLog(user.uid, date, checks);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      const habit = habits.find(h => h.id === id);
      if (habit) {
          await createHabit(user.uid, habit.name);
      }
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
      await commitOnboarding(user.uid, habitNames, timezone);
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      repairTokens: repairTokens,
      dataYear: new Date().getFullYear(),
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      repairDay,
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    repairDailyLog,
    commitOnboarding,
    getWeekParams
} from '../lib/firestore';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  repairDay: (date: string, checks: Record<string, boolean>) => Promise<void>;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  dataYear: new Date().getFullYear(),
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [repairTokens, setRepairTokens] = useState<number>(3);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const currentYear = new Date().getFullYear().toString();
    const today = new Date();
    const { year: currentWeekYear, weekId: currentWeekId } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs (Year-based + Week Transformation)
    // We listen to the current year collection.
    // If the current week actually falls in the previous year (e.g. Dec 31 start), we might miss it.
    // So we primarily listen to `currentYear`.
    // And if `currentWeekYear` != `currentYear`, we listen to that specific doc too.

    const yearCollection = collection(db, `users/${userId}/${currentYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];
        let currentRepairTokens = 3;

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // Check if this is the current week for repair tokens
            if (weekId === currentWeekId && currentYear === currentWeekYear) {
                currentRepairTokens = typeof data.repairsLeft === 'number' ? data.repairsLeft : 3;
            }

            // Transform day arrays to DailyLog
            // We need to calculate dates from weekId. 
            // weekId format: "weekN"
            const weekNum = parseInt(weekId.replace('week', ''));
            // Estimate start date. 
            // Week 1 starts on first Sunday of year.
            const yearDate = new Date(parseInt(currentYear), 0, 1);
            while(yearDate.getDay() !== 0) yearDate.setDate(yearDate.getDate() + 1);

            // Add weeks
            yearDate.setDate(yearDate.getDate() + (weekNum - 1) * 7);
            const weekStartMs = yearDate.getTime();

            const days = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];

            days.forEach((dayName, idx) => {
                 const habitIds = data[dayName];
                 if (Array.isArray(habitIds) && habitIds.length > 0) {
                     const logDate = new Date(weekStartMs + (idx * 86400000));
                     // Formatting
                     const y = logDate.getFullYear();
                     const m = String(logDate.getMonth() + 1).padStart(2, '0');
                     const d = String(logDate.getDate()).padStart(2, '0');
                     const dateStr = `${y}-${m}-${d}`;

                     const checks: Record<string, boolean> = {};
                     habitIds.forEach((hid: string) => checks[hid] = true);

                     allLogs.push({
                         date: dateStr,
                         weekId: weekId,
                         checks
                     });
                 }
            });
        });

        setLogs(prev => {
            // Merge? No, just replace for this year context. 
            // In a real app we might merge if we had multiple listeners.
            return allLogs; 
        });

        // Only set repair tokens if we found the current week. 
        // If not found (new week not created yet), it defaults to 3 in UI logic usually, but here we set it.
        // If the doc doesn't exist in snapshot, it means no data logged yet for this week.
        const hasCurrentWeek = snapshot.docs.some(d => d.id === currentWeekId);
        if (!hasCurrentWeek && currentYear === currentWeekYear) {
             setRepairTokens(3);
        } else if (hasCurrentWeek && currentYear === currentWeekYear) {
             setRepairTokens(currentRepairTokens);
        }
    });

    // B2. Edge Case: If current week is in a different year (e.g. late Dec/early Jan transition handled by Sunday logic)
    // For MVP simplicity, we assume user is mostly viewing current year. 
    // If strict overlap support is needed, we would add a listener for `doc(db, users, uid, currentWeekYear, currentWeekId)`.

    // C. User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      await toggleHabitCompletion(user.uid, habitId, date);
  };

  const repairDay = async (date: string, checks: Record<string, boolean>) => {
      if (!user) return;
      await repairDailyLog(user.uid, date, checks);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      const habit = habits.find(h => h.id === id);
      if (habit) {
          await createHabit(user.uid, habit.name);
      }
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
      await commitOnboarding(user.uid, habitNames, timezone);
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      repairTokens: repairTokens,
      dataYear: new Date().getFullYear(),
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      repairDay,
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { User, Check, Zap, X, AlertTriangle, Lock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Today: React.FC = () => {
  const { state, toggleHabit, repairDay } = useApp();
  const navigate = useNavigate();

  // Repair Modal State
  const [repairDate, setRepairDate] = useState<string | null>(null);
  const [repairChecks, setRepairChecks] = useState<Record<string, boolean>>({});
  const [isRepairing, setIsRepairing] = useState(false);

  // Date Logic (Local Time Safe)
  const today = new Date();
  const toLocalISO = (d: Date) => {
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };

  const todayStr = toLocalISO(today);
  const dayOfWeek = today.getDay(); // 0 (Sun) - 6 (Sat)

  // Calculate Start of Week (Sunday)
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - dayOfWeek);

  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);

  // Generate Week Days
  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    const dateStr = toLocalISO(d);
    return {
        dateStr,
        label: d.toLocaleDateString('en-US', { weekday: 'narrow' }),
        dayNum: d.getDate(),
        isToday: dateStr === todayStr,
        isFuture: dateStr > todayStr
    };
  });

  const displayHabits = state.habits.filter(h => h.status === 'active');

  // Stats Logic
  let totalCompleted = 0;
  let totalPotential = 0;

  displayHabits.forEach(h => {
      weekDays.forEach(day => {
          const isApplicable = day.dateStr >= h.activeFrom && (!h.inactiveFrom || day.dateStr < h.inactiveFrom);
          if (isApplicable && !day.isFuture) {
              totalPotential++;
              const log = state.logs.find(l => l.date === day.dateStr);
              if (log && log.checks && log.checks[h.id]) {
                  totalCompleted++;
              }
          }
      });
  });

  const weeklyPercentage = totalPotential > 0 ? (totalCompleted / totalPotential) * 100 : 0;

  // --- INTERACTION HANDLERS ---

  const handleCellClick = (id: string, date: string, isFuture: boolean, isNA: boolean) => {
    if (isFuture || isNA) return;

    if (date === todayStr) {
        // Today: Instant toggle
        toggleHabit(id, date);
    } else {
        // Past Day Logic
        if (state.repairTokens > 0) {
            // Editable: Open Modal
            openRepairModal(date);
        } else {
            // Locked: Show Alert
            alert("No repair tokens remaining this week.");
        }
    }
  };

  const openRepairModal = (date: string) => {
      const log = state.logs.find(l => l.date === date);
      const currentChecks = log ? { ...log.checks } : {};
      setRepairChecks(currentChecks);
      setRepairDate(date);
  };

  const toggleRepairCheck = (habitId: string) => {
      setRepairChecks(prev => {
          const next = { ...prev };
          if (next[habitId]) {
              delete next[habitId];
          } else {
              next[habitId] = true;
          }
          return next;
      });
  };

  const saveRepair = async () => {
      if (!repairDate) return;

      // Strict Check
      if (state.repairTokens <= 0) {
          alert("No repairs remaining.");
          setRepairDate(null);
          return;
      }

      setIsRepairing(true);
      try {
          // Send the full repairChecks object. 
          // The API will decrement 1 token per confirmed save (transactional).
          await repairDay(repairDate, repairChecks);
          setRepairDate(null);
      } catch (e: any) {
          alert(e.message);
      } finally {
          setIsRepairing(false);
      }
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark relative font-sans">
      {/* Header */}
      <header className="px-6 py-5 flex items-center justify-between sticky top-0 z-50 bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-xl border-b border-ledger-border dark:border-ledger-borderDark">
        <div>
            <h1 className="text-base font-bold text-ledger-text dark:text-ledger-textDark tracking-tight">
                Current Week
            </h1>
            <p className="text-xs text-ledger-muted mt-0.5 font-medium">
                {startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </p>
        </div>
        <button onClick={() => navigate('/account')} className="p-2 -mr-2 text-ledger-text dark:text-ledger-textDark hover:opacity-70 transition-opacity">
          <User size={22} strokeWidth={2} />
        </button>
      </header>

      {/* KPI Section */}
      <div className="px-6 py-6 border-b border-ledger-border dark:border-ledger-borderDark bg-white dark:bg-[#111111]">
         <div className="flex items-center justify-between">
             <div>
                <div className="text-4xl font-extrabold text-ledger-text dark:text-ledger-textDark tracking-tight">
                    {Math.round(weeklyPercentage)}%
                </div>
                <div className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mt-1">
                    {totalCompleted} / {totalPotential} Checks
                </div>
             </div>

             <div className="flex flex-col items-end gap-1">
                 <div className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md border transition-colors ${state.repairTokens > 0 ? 'bg-gray-100 dark:bg-white/10 border-transparent' : 'bg-red-50 dark:bg-red-900/10 border-red-100 dark:border-red-900/20 text-red-600'}`}>
                    <Zap size={14} className={state.repairTokens > 0 ? "text-ledger-accent" : "text-red-500"} fill="currentColor" />
                    <span className={`text-xs font-bold ${state.repairTokens > 0 ? 'text-ledger-text dark:text-ledger-textDark' : 'text-red-600 dark:text-red-500'}`}>
                        {state.repairTokens}
                    </span>
                 </div>
                 <span className="text-[10px] font-medium text-ledger-muted">Tokens Left</span>
             </div>
         </div>
      </div>

      {/* Main Grid */}
      <div className="flex-1 overflow-auto no-scrollbar pb-24 relative bg-ledger-bg dark:bg-ledger-bgDark">
         <table className="border-collapse min-w-full">
            <thead className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark shadow-sm">
                <tr>
                    <th className="sticky left-0 top-0 z-50 bg-ledger-bg dark:bg-ledger-bgDark border-b border-r border-gray-100 dark:border-gray-800 px-4 py-4 text-left shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)] dark:shadow-none">
                        <span className="font-bold text-[10px] text-ledger-muted uppercase tracking-wider whitespace-nowrap">Task</span>
                    </th>
                    {weekDays.map(d => (
                        <th key={d.dateStr} className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark border-b border-gray-100 dark:border-gray-800 px-2 py-4 min-w-[60px]">
                            <div className={`flex flex-col items-center justify-center gap-1.5 ${d.isToday ? 'text-ledger-accent' : 'text-ledger-muted'}`}>
                                <span className="text-[10px] font-bold uppercase tracking-wider">{d.label}</span>
                                <span className={`text-xs font-bold w-6 h-6 flex items-center justify-center rounded-full transition-colors ${d.isToday ? 'bg-ledger-accent text-white shadow-md' : 'bg-transparent text-inherit'}`}>
                                    {d.dayNum}
                                </span>
                            </div>
                        </th>
                    ))}
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800/50">
                {displayHabits.map(habit => (
                    <tr key={habit.id} className="group bg-white dark:bg-ledger-bgDark">
                        <td className="sticky left-0 z-30 bg-white dark:bg-ledger-bgDark border-r border-gray-100 dark:border-gray-800 px-4 py-3 whitespace-nowrap shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)] dark:shadow-none">
                            <span className="text-sm font-semibold text-ledger-text dark:text-ledger-textDark">
                                {habit.name}
                            </span>
                        </td>

                        {weekDays.map(d => {
                             const log = state.logs.find(l => l.date === d.dateStr);
                             const isCompleted = log?.checks && log.checks[habit.id];
                             const isApplicable = d.dateStr >= habit.activeFrom && (!habit.inactiveFrom || d.dateStr < habit.inactiveFrom);
                             const isNA = !isApplicable;

                             // Logic
                             // STRICT past check
                             const isPast = d.dateStr < todayStr;
                             const isLocked = isPast && state.repairTokens <= 0;

                             // Styles
                             let cellContent = null;
                             let cellClass = "w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-200 border-2 mx-auto relative overflow-hidden";

                             if (d.isFuture) {
                                 cellClass += " border-transparent bg-gray-50 dark:bg-white/5 opacity-20 cursor-not-allowed";
                             } else if (isNA) {
                                 cellClass += " border-transparent bg-gray-100 dark:bg-white/5 cursor-not-allowed";
                                 cellContent = <div className="w-4 h-0.5 bg-gray-300 dark:bg-gray-700 rounded-full" />;
                             } else if (isCompleted) {
                                 cellClass += " border-ledger-accent bg-ledger-accent text-white shadow-sm";
                                 cellContent = <Check size={20} strokeWidth={4} />;
                                 if (isLocked) {
                                     // Completed but locked (can't undo)
                                     cellClass += " opacity-80 grayscale-[0.5]";
                                 }
                             } else {
                                 // Not completed
                                 if (isLocked) {
                                     // Locked and Empty
                                     cellClass += " border-gray-100 dark:border-gray-800 bg-gray-100/50 dark:bg-white/5 cursor-not-allowed";
                                 } else if (isPast) {
                                     // Editable Past (Has Tokens)
                                     cellClass += " border-dashed border-gray-300 dark:border-gray-600 bg-white dark:bg-ledger-surfaceDark hover:border-ledger-accent cursor-pointer group-hover:bg-gray-50 dark:group-hover:bg-white/5";
                                 } else {
                                     // Today (Default)
                                     cellClass += " border-gray-200 dark:border-gray-700 bg-white dark:bg-ledger-surfaceDark hover:border-ledger-accent cursor-pointer";
                                 }
                             }

                            return (
                                <td key={d.dateStr} className="px-2 py-2">
                                     <button
                                        onClick={() => handleCellClick(habit.id, d.dateStr, d.isFuture, isNA)}
                                        disabled={d.isFuture || isNA} 
                                        className="active:scale-95 transition-transform block w-full disabled:active:scale-100 disabled:cursor-default"
                                     >
                                         <div className={cellClass}>
                                             {cellContent}

                                             {/* Locked Indicator Overlay */}
                                             {isLocked && !isNA && (
                                                <div className="absolute inset-0 flex items-center justify-center text-ledger-muted/50 bg-white/10 dark:bg-black/10">
                                                    <Lock size={14} strokeWidth={2.5} />
                                                </div>
                                             )}

                                             {/* Editable Past Indicator - Only show if NO check and NOT locked */}
                                             {isPast && !isLocked && !isNA && !isCompleted && (
                                                 <div className="absolute top-0 right-0 p-1">
                                                    <div className="w-1.5 h-1.5 rounded-full bg-ledger-accent/40" />
                                                 </div>
                                             )}
                                         </div>
                                     </button>
                                </td>
                            );
                        })}
                    </tr>
                ))}
            </tbody>
         </table>
      </div>

      {/* REPAIR MODAL */}
      {repairDate && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setRepairDate(null)}>
            <div className="bg-white dark:bg-[#1A1A1A] rounded-2xl w-full max-w-sm overflow-hidden flex flex-col max-h-[80vh] shadow-2xl" onClick={e => e.stopPropagation()}>
                <div className="p-6 border-b border-gray-100 dark:border-gray-800 flex justify-between items-center bg-gray-50 dark:bg-white/5">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <h3 className="text-lg font-bold text-ledger-text dark:text-ledger-textDark">Edit Past Log</h3>
                            <div className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-ledger-accent text-white">
                                {state.repairTokens} Tokens Left
                            </div>
                        </div>
                        <p className="text-sm text-ledger-muted">{new Date(repairDate).toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric'})}</p>
                    </div>
                    <button onClick={() => setRepairDate(null)} className="p-2 bg-gray-200 dark:bg-white/10 rounded-full hover:bg-gray-300 dark:hover:bg-white/20 transition-colors">
                        <X size={18} />
                    </button>
                </div>

                <div className="p-4 overflow-y-auto flex-1 space-y-2">
                    {/* Only show habits applicable for that day */}
                    {state.habits.filter(h => repairDate >= h.activeFrom && (!h.inactiveFrom || repairDate < h.inactiveFrom)).map(h => (
                        <button 
                            key={h.id}
                            onClick={() => toggleRepairCheck(h.id)}
                            className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all ${repairChecks[h.id] ? 'bg-ledger-accent text-white border-ledger-accent' : 'bg-transparent border-gray-200 dark:border-gray-700 text-ledger-text dark:text-ledger-textDark hover:bg-gray-50 dark:hover:bg-white/5'}`}
                        >
                            <span className="font-semibold">{h.name}</span>
                            {repairChecks[h.id] ? <Check size={20} strokeWidth={3} /> : <div className="w-5 h-5 rounded-full border-2 border-gray-300 dark:border-gray-600" />}
                        </button>
                    ))}
                    {state.habits.length === 0 && <p className="text-center text-ledger-muted py-4">No habits to edit.</p>}
                </div>

                <div className="p-4 bg-white dark:bg-[#1A1A1A] border-t border-gray-100 dark:border-gray-800">
                    <div className="flex items-start gap-3 mb-4 p-3 bg-amber-50 dark:bg-amber-900/10 rounded-lg text-amber-800 dark:text-amber-400 text-xs leading-relaxed">
                            <AlertTriangle size={16} className="shrink-0 mt-0.5" />
                            <span>This action will consume <strong>1 Repair Token</strong>. You have {state.repairTokens} remaining this week.</span>
                    </div>

                    <button 
                        onClick={saveRepair} 
                        disabled={isRepairing}
                        className="w-full h-12 bg-ledger-accent hover:bg-ledger-accentHover text-white font-bold rounded-xl flex items-center justify-center disabled:opacity-50 transition-colors shadow-lg shadow-ledger-accent/20"
                    >
                        {isRepairing ? 'Processing...' : 'Confirm & Use Token'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    repairDailyLog,
    commitOnboarding,
    getWeekParams
} from '../lib/firestore';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  repairDay: (date: string, checks: Record<string, boolean>) => Promise<void>;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  dataYear: new Date().getFullYear(),
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [repairTokens, setRepairTokens] = useState<number>(3);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const currentYear = new Date().getFullYear().toString();

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs (Year-based + Week Transformation)
    const yearCollection = collection(db, `users/${userId}/${currentYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        // Recalculate current params inside callback to ensure freshness
        const today = new Date();
        const { year: liveYear, weekId: liveWeekId } = getWeekParams(today);

        let allLogs: DailyLog[] = [];
        let currentRepairTokens = 3;
        let foundCurrentWeek = false;

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // Check if this is the current week for repair tokens
            // Ensure we are comparing against the live calculated week
            if (weekId === liveWeekId && currentYear === liveYear) {
                currentRepairTokens = typeof data.repairsLeft === 'number' ? data.repairsLeft : 3;
                foundCurrentWeek = true;
            }

            // Transform day arrays to DailyLog
            const weekNum = parseInt(weekId.replace('week', ''));
            const yearDate = new Date(parseInt(currentYear), 0, 1);
            while(yearDate.getDay() !== 0) yearDate.setDate(yearDate.getDate() + 1);

            yearDate.setDate(yearDate.getDate() + (weekNum - 1) * 7);
            const weekStartMs = yearDate.getTime();

            const days = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];

            days.forEach((dayName, idx) => {
                 const habitIds = data[dayName];
                 if (Array.isArray(habitIds) && habitIds.length > 0) {
                     const logDate = new Date(weekStartMs + (idx * 86400000));
                     const y = logDate.getFullYear();
                     const m = String(logDate.getMonth() + 1).padStart(2, '0');
                     const d = String(logDate.getDate()).padStart(2, '0');
                     const dateStr = `${y}-${m}-${d}`;

                     const checks: Record<string, boolean> = {};
                     habitIds.forEach((hid: string) => checks[hid] = true);

                     allLogs.push({
                         date: dateStr,
                         weekId: weekId,
                         checks
                     });
                 }
            });
        });

        setLogs(allLogs);

        // If the current week doc doesn't exist yet, we default to 3 tokens.
        if (!foundCurrentWeek && currentYear === liveYear) {
             setRepairTokens(3);
        } else if (foundCurrentWeek && currentYear === liveYear) {
             setRepairTokens(currentRepairTokens);
        }
    });

    // C. User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      await toggleHabitCompletion(user.uid, habitId, date);
  };

  const repairDay = async (date: string, checks: Record<string, boolean>) => {
      if (!user) return;
      await repairDailyLog(user.uid, date, checks);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      const habit = habits.find(h => h.id === id);
      if (habit) {
          await createHabit(user.uid, habit.name);
      }
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
      await commitOnboarding(user.uid, habitNames, timezone);
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      repairTokens: repairTokens,
      dataYear: new Date().getFullYear(),
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      repairDay,
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    repairDailyLog,
    commitOnboarding,
    getWeekParams
} from '../lib/firestore';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  repairDay: (date: string, checks: Record<string, boolean>) => Promise<void>;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  dataYear: new Date().getFullYear(),
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [repairTokens, setRepairTokens] = useState<number>(3);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const today = new Date();
    // CRITICAL: Use the year from getWeekParams to ensure we listen to the correct collection
    // even if the week spans across a year boundary.
    const { year: currentWeekYear, weekId: currentWeekId } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs (Listen to the Calculated Year Collection)
    const yearCollection = collection(db, `users/${userId}/${currentWeekYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];
        let currentRepairTokens = 3;
        let foundCurrentWeek = false;

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // Check if this is the current week for repair tokens
            if (weekId === currentWeekId) {
                currentRepairTokens = typeof data.repairsLeft === 'number' ? data.repairsLeft : 3;
                foundCurrentWeek = true;
            }

            // Transform day arrays to DailyLog
            const weekNum = parseInt(weekId.replace('week', ''));
            const yearDate = new Date(parseInt(currentWeekYear), 0, 1);

            // Align to first Sunday of the year (matching getWeekParams logic)
            while(yearDate.getDay() !== 0) yearDate.setDate(yearDate.getDate() + 1);

            // Add weeks
            yearDate.setDate(yearDate.getDate() + (weekNum - 1) * 7);
            const weekStartMs = yearDate.getTime();

            const days = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];

            days.forEach((dayName, idx) => {
                 const habitIds = data[dayName];
                 if (Array.isArray(habitIds) && habitIds.length > 0) {
                     const logDate = new Date(weekStartMs + (idx * 86400000));
                     // Formatting
                     const y = logDate.getFullYear();
                     const m = String(logDate.getMonth() + 1).padStart(2, '0');
                     const d = String(logDate.getDate()).padStart(2, '0');
                     const dateStr = `${y}-${m}-${d}`;

                     const checks: Record<string, boolean> = {};
                     habitIds.forEach((hid: string) => checks[hid] = true);

                     allLogs.push({
                         date: dateStr,
                         weekId: weekId,
                         checks
                     });
                 }
            });
        });

        setLogs(allLogs);

        // If the current week doc doesn't exist yet, we default to 3 tokens.
        // If it exists, we use the value from Firestore.
        if (!foundCurrentWeek) {
             setRepairTokens(3);
        } else {
             setRepairTokens(currentRepairTokens);
        }
    });

    // C. User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      await toggleHabitCompletion(user.uid, habitId, date);
  };

  const repairDay = async (date: string, checks: Record<string, boolean>) => {
      if (!user) return;
      await repairDailyLog(user.uid, date, checks);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      const habit = habits.find(h => h.id === id);
      if (habit) {
          await createHabit(user.uid, habit.name);
      }
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
      await commitOnboarding(user.uid, habitNames, timezone);
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
