            {authError && <div className="mt-4 p-3 bg-red-50 dark:bg-red-900/20 text-red-600 rounded-lg text-sm">{authError}</div>}

            <div className="mt-8 space-y-4">
                <Button fullWidth onClick={handleAuth} disabled={isLoading}>
                    {isLoading ? 'Processing...' : (isSignUp ? 'Sign Up' : 'Log In')}
                </Button>
                <button onClick={() => { setIsSignUp(!isSignUp); setAuthError(''); }} className="w-full text-center text-xs text-ledger-muted hover:text-ledger-text">
                    {isSignUp ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
                </button>
            </div>
         </div>
      </div>
    );
  }

  // Selection Step
  if (step === 'selection') {
    return (
      <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col max-w-md mx-auto relative animate-fade-in">
        <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
