                                     <button
                                        onClick={() => handleCellClick(habit.id, d.dateStr, d.isFuture)}
                                        disabled={d.isFuture} 
                                        className="block w-full disabled:cursor-auto"
                                     >
                                         <div className={cellClass}>
                                             {cellContent}

                                             {/* Past Indicator for unfilled days to hint editability */}
                                             {isPast && !isCompleted && (
                                                 <div className="absolute top-0 right-0 p-1">
                                                    <div className="w-1.5 h-1.5 rounded-full bg-ledger-accent/20" />
                                                 </div>
                                             )}
                                         </div>
                                     </button>
                                </td>
                            );
                        })}
                    </tr>
                ))}
            </tbody>
         </table>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ChevronLeft, ChevronRight } from 'lucide-react';

type ViewMode = 'Year' | 'Month' | 'Week';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [view, setView] = useState<ViewMode>('Year');

  // Navigation States
  const [selectedWeekOffset, setSelectedWeekOffset] = useState(0); 
  const [selectedMonthOffset, setSelectedMonthOffset] = useState(0); 

  const today = new Date();
  const currentYear = today.getFullYear();
  const todayStr = today.toISOString().split('T')[0];

  // Helper: Is habit applicable on date?
  const isApplicable = (habitId: string, dateStr: string) => {
      const habit = state.habits.find(h => h.id === habitId);
      if (!habit) return false;
      return dateStr >= habit.activeFrom && (!habit.inactiveFrom || dateStr < habit.inactiveFrom);
  };

  const getWeekNumber = (d: Date) => {
      const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
      date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
      const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const weekNo = Math.ceil(( ( (date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
      return weekNo - 1; 
  };

  const currentWeekIndex = getWeekNumber(today);

  // --- VIEW: YEAR ---
  const renderYearView = () => {
    const weeks = [];
    let d = new Date(currentYear, 0, 1);

    // Adjust to start of week (Sunday)
    while (d.getDay() !== 0) {
        d.setDate(d.getDate() - 1);
    }

    for (let i = 0; i < 53; i++) {
        const weekStart = new Date(d);
        const weekEnd = new Date(d);
        weekEnd.setDate(weekEnd.getDate() + 6);

        const startStr = weekStart.toISOString().split('T')[0];
        const endStr = weekEnd.toISOString().split('T')[0];

        // Compute "Days Logged" (Any activity on that day)
        const logsInWeek = state.logs.filter(l => l.date >= startStr && l.date <= endStr);
        const activeDays = logsInWeek.filter(l => Object.keys(l.checks || {}).length > 0).length;

        const fillPercent = (activeDays / 7) * 100;

        weeks.push({ 
            id: i, 
            fillPercent, 
            startDate: weekStart,
            isCurrent: i === currentWeekIndex,
            isFuture: i > currentWeekIndex,
            weekNum: i + 1
        });

        d.setDate(d.getDate() + 7);
    }

    return (
        <div className="grid grid-cols-7 gap-3 px-2">
            {weeks.map((w) => (
                <button
                    key={w.id}
                    disabled={w.isFuture}
                    onClick={() => {
                        const offset = w.id - currentWeekIndex;
                        setSelectedWeekOffset(offset);
                        setView('Week');
                    }}
                    className={`aspect-square rounded-md border relative overflow-hidden flex items-end justify-center transition-all
                        ${w.isFuture 
                             ? 'border-gray-100 dark:border-gray-800 opacity-20 cursor-default' 
                             : 'border-gray-200 dark:border-gray-800 cursor-pointer hover:border-ledger-accent'
                        }
                        ${w.isCurrent ? 'ring-2 ring-ledger-accent ring-offset-2 dark:ring-offset-ledger-bgDark' : ''}
                    `}
                >
                    {!w.isFuture && (
                        <div 
                            className="absolute inset-x-0 bottom-0 bg-ledger-accent transition-all duration-700 ease-out opacity-80"
                            style={{ height: `${Math.max(w.fillPercent, 0)}%` }}
                        />
                    )}
                    <span className="relative z-10 text-[10px] font-bold text-ledger-text dark:text-ledger-textDark mix-blend-difference mb-1">
                        {w.weekNum}
                    </span>
                </button>
            ))}
        </div>
    );
  };

  // --- VIEW: MONTH ---
  const renderMonthView = () => {
    const targetDate = new Date(today.getFullYear(), today.getMonth() + selectedMonthOffset, 1);
    const targetMonth = targetDate.getMonth();
    const targetYear = targetDate.getFullYear();

    const minOffset = -today.getMonth();
    const maxOffset = 11 - today.getMonth();
    const isPrevDisabled = selectedMonthOffset <= minOffset;
    const isNextDisabled = selectedMonthOffset >= maxOffset;

    const daysInMonth = new Date(targetYear, targetMonth + 1, 0).getDate();
    const firstDayIndex = new Date(targetYear, targetMonth, 1).getDay();

    const days = Array.from({ length: daysInMonth }, (_, i) => {
        const d = new Date(targetYear, targetMonth, i + 1);
        const dateStr = d.toISOString().split('T')[0];
        const log = state.logs.find(l => l.date === dateStr);
        const hasLog = log && Object.keys(log.checks || {}).length > 0;
        const isToday = dateStr === todayStr;
        return { dateStr, dayNum: i + 1, hasLog, isToday };
    });

    const blanks = Array.from({ length: firstDayIndex }, (_, i) => i);

    return (
        <div className="px-4">
             {/* Header Controls */}
             <div className="flex items-center justify-between mb-6 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p - 1)} 
                    disabled={isPrevDisabled}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark uppercase tracking-wide">
                      {targetDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p + 1)} 
                    disabled={isNextDisabled} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

             <div className="grid grid-cols-7 gap-3">
                {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="text-center text-[10px] font-bold text-ledger-muted uppercase mb-2">{d}</div>
                ))}

                {blanks.map(i => <div key={`blank-${i}`} />)}

                {days.map(d => {
                    // Logic for styles
                    let className = "aspect-square rounded-lg flex items-center justify-center text-sm font-semibold transition-all relative ";

                    if (d.isToday) {
                        // NEW TODAY DESIGN: Bordered.
                        if (d.hasLog) {
                            // Filled + Strong Border
                            className += "bg-ledger-accent text-white shadow-sm border-2 border-ledger-text dark:border-white";
                        } else {
                            // Empty + Accent Border + Accent Text
                            className += "bg-transparent text-ledger-accent border-2 border-ledger-accent";
                        }
                    } else {
                        // Normal Days
                        if (d.hasLog) {
                             className += "bg-ledger-accent text-white shadow-sm";
                        } else {
                             className += "bg-white dark:bg-ledger-surfaceDark text-ledger-muted border border-gray-100 dark:border-gray-800";
                        }
                    }

                    return (
                        <div key={d.dateStr} className={className}>
                            {d.dayNum}
                            {d.isToday && !d.hasLog && (
                                <div className="absolute -bottom-1 w-1 h-1 bg-ledger-accent rounded-full" />
                            )}
                        </div>
                    );
                })}
             </div>
        </div>
    );
  };

  // --- VIEW: WEEK ---
  const renderWeekView = () => {
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay();
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff);

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];

          let possible = 0;
          let completed = 0;

          state.habits.forEach(h => {
              if (isApplicable(h.id, dateStr)) {
                  possible++;
                  const log = state.logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      completed++;
                  }
              }
          });

          const pct = possible > 0 ? (completed / possible) * 100 : 0;
          const isDifferentYear = d.getFullYear() !== currentYear;
          const isToday = dateStr === todayStr;

          return { 
              label: d.toLocaleDateString('en-US', { weekday: 'narrow' }), 
              pct, 
              dateStr,
              isDifferentYear,
              isToday
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      const isEarliestWeek = selectedWeekOffset <= -currentWeekIndex;

      return (
          <div className="px-4">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p - 1)} 
                    disabled={isEarliestWeek}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p + 1)} 
                    disabled={selectedWeekOffset >= 0} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
                      <div key={i} className={`flex flex-col items-center gap-2 flex-1 h-full justify-end group ${d.isDifferentYear ? 'opacity-30 grayscale' : ''}`}>
                          <div className="w-full bg-gray-100 dark:bg-white/5 rounded-t-sm relative h-full flex items-end overflow-hidden">
                              <div 
                                  className={`w-full bg-ledger-accent transition-all duration-500 ease-out rounded-t-sm ${d.isDifferentYear ? 'bg-gray-400' : ''}`}
                                  style={{ height: `${Math.max(d.pct, 4)}%` }} 
                              />
                          </div>

                          {/* NEW TODAY DESIGN FOR WEEK: Highlighted Label */}
                          <div className={`
                             flex items-center justify-center rounded-md px-1.5 py-0.5
                             ${d.isToday 
                                ? 'bg-ledger-accent text-white shadow-sm' 
                                : 'bg-transparent text-ledger-muted'
                             }
                          `}>
                              <span className="text-xs font-bold uppercase">{d.label}</span>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-4 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark px-2">Progress</h1>
      </header>

      {/* View Switcher */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-xl mb-8 mx-2">
          {(['Year', 'Month', 'Week'] as ViewMode[]).map(mode => (
              <button 
                key={mode}
                onClick={() => {
                    setView(mode);
                    if(mode === 'Week') setSelectedWeekOffset(0);
                    if(mode === 'Month') setSelectedMonthOffset(0);
                }}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wide rounded-lg transition-all ${view === mode ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {mode}
              </button>
          ))}
      </div>

      <div className="flex-1 animate-fade-in">
          {view === 'Year' && (
              <div>
                  <h3 className="px-2 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{currentYear} Overview</h3>
                  {renderYearView()}
              </div>
          )}
          {view === 'Month' && renderMonthView()}
          {view === 'Week' && renderWeekView()}
      </div>
    </div>
  );
};

import { 
  collection, 
  doc, 
  setDoc, 
  updateDoc, 
  serverTimestamp, 
  query, 
  getDocs, 
  writeBatch, 
  runTransaction,
  deleteDoc,
  deleteField,
  limit,
  Timestamp,
  DocumentReference,
  arrayUnion,
  arrayRemove
} from "firebase/firestore";
import { db, auth } from "./firebase";
import { deleteUser } from "firebase/auth";

// --- HELPERS (Time Truth) ---

// Single source of truth for Local ISO Date Strings (YYYY-MM-DD)
export const toLocalISOString = (d: Date) => {
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
};

export const getTodayStr = () => {
    return toLocalISOString(new Date());
};

export const getWeekRange = (year: number, weekNum: number) => {
    const jan1 = new Date(year, 0, 1);
    const dayOfWeekJan1 = jan1.getDay(); // 0(Sun)..6(Sat)

    // End of Week 1 (First Saturday)
    // If Jan 1 is Sat(6), offset is 0.
    // If Jan 1 is Sun(0), offset is 6.
    const offsetToSat = 6 - dayOfWeekJan1;
    const endOfWeek1 = new Date(jan1);
    endOfWeek1.setDate(jan1.getDate() + offsetToSat);

    if (weekNum === 1) {
        return { start: jan1, end: endOfWeek1 };
    }

    // Week > 1
    // Start = EndOfWeek1 + 1 (First Sunday) + (weekNum - 2) weeks
    const start = new Date(endOfWeek1);
    start.setDate(start.getDate() + 1 + (weekNum - 2) * 7);

    const end = new Date(start);
    end.setDate(start.getDate() + 6);

    // Cap at Dec 31
    const dec31 = new Date(year, 11, 31);
    if (end > dec31) {
        // This is the last week, clamp it
        return { start, end: dec31 };
    }

    return { start, end };
};

export const getWeekParams = (date: Date = new Date()) => {
    const year = date.getFullYear();
    const d = new Date(date);
    d.setHours(0,0,0,0);

    // Calculate Week Number based on strict Year Boundaries
    // Week 1: Jan 1 to First Saturday
    // Week 2+: Sunday to Saturday

    const jan1 = new Date(year, 0, 1);
    const dayOfWeekJan1 = jan1.getDay();

    // Date of first Saturday (End of Week 1)
    const firstSat = new Date(jan1);
    firstSat.setDate(jan1.getDate() + (6 - dayOfWeekJan1));

    let weekNum = 1;

    if (d > firstSat) {
        // Calculate days passed since the end of Week 1
        // Treat First Sunday (firstSat + 1) as Day 0 of the rest of the year
        const firstSun = new Date(firstSat);
        firstSun.setDate(firstSat.getDate() + 1);

        const diffTime = d.getTime() - firstSun.getTime();
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

        weekNum = 2 + Math.floor(diffDays / 7);
    }

    const { start: weekStart } = getWeekRange(year, weekNum);
    const startOfWeekStr = toLocalISOString(weekStart);

    return {
        year: year.toString(),
        weekId: `week${weekNum}`,
        startOfWeekStr,
        dayName: date.toLocaleDateString('en-US', { weekday: 'short' }).toLowerCase() // sun, mon, tue...
    };
};

// Canonicalize name
export const getCanonicalName = (name: string): string => {
    return name.toLowerCase().replace(/[\s\p{P}\p{S}]/gu, ''); 
};

// --- TYPES ---

export interface FirestoreHabit {
  name: string;
  canonicalName: string;
  status: 'active' | 'archived';
  activeFrom: string;
  inactiveFrom: string | null;
  sortOrder: number;
  createdAt: any;
}

// --- CORE ACTIONS ---

export const checkUserHasHabits = async (userId: string): Promise<boolean> => {
    const habitsRef = collection(db, `users/${userId}/habits`);
    const q = query(habitsRef, limit(1));
    const snap = await getDocs(q);
    return !snap.empty;
};

// 1. Toggle Habit (Writes to Year/Week/DayArray)
export const toggleHabitCompletion = async (
  userId: string, 
  habitId: string, 
  dateStr: string
) => {
  const parts = dateStr.split('-');
  const localDate = new Date(parseInt(parts[0]), parseInt(parts[1])-1, parseInt(parts[2]));

  const { year, weekId, dayName } = getWeekParams(localDate);

  // Path: users/{uid}/{year}/{weekId}
  const weekRef = doc(db, `users/${userId}/${year}/${weekId}`);

  await runTransaction(db, async (transaction) => {
    const weekSnap = await transaction.get(weekRef);

    if (!weekSnap.exists()) {
        // Create week doc if missing
        transaction.set(weekRef, {
            [dayName]: [habitId],
            updatedAt: serverTimestamp()
        });
    } else {
        const data = weekSnap.data();
        const currentDayHabits = data[dayName] || [];
        const exists = currentDayHabits.includes(habitId);

        if (exists) {
            transaction.update(weekRef, {
                [dayName]: arrayRemove(habitId),
                updatedAt: serverTimestamp()
            });
        } else {
            transaction.update(weekRef, {
                [dayName]: arrayUnion(habitId),
                updatedAt: serverTimestamp()
            });
        }
    }
  });
};

// 2. Create Habit
export const createHabit = async (userId: string, name: string) => {
    const canon = getCanonicalName(name);
    if (!canon) throw new Error("Invalid habit name.");

    const habitsRef = collection(db, `users/${userId}/habits`);
    const indexRef = doc(db, `users/${userId}/habitNameIndex`, canon);

    await runTransaction(db, async (transaction) => {
        const indexSnap = await transaction.get(indexRef);
        if (indexSnap.exists()) throw new Error(`Habit "${name}" already exists.`);

        const snapshot = await getDocs(query(habitsRef)); 
        const activeCount = snapshot.docs.filter(d => d.data().status === 'active').length;
        if (activeCount >= 15) throw new Error("Max 15 active habits allowed.");

        const count = snapshot.size;
        const newHabitRef = doc(habitsRef);
        const todayStr = getTodayStr();

        transaction.set(indexRef, {
            habitId: newHabitRef.id,
            createdAt: serverTimestamp()
        });

        transaction.set(newHabitRef, {
            name,
            canonicalName: canon,
            status: 'active',
            activeFrom: todayStr,
            inactiveFrom: null,
            sortOrder: count,
            createdAt: serverTimestamp(),
            updatedAt: serverTimestamp()
        });
    });
};

// 3. Rename Habit
export const renameHabit = async (userId: string, habitId: string, newName: string) => {
    const newCanon = getCanonicalName(newName);
    if (!newCanon) throw new Error("Invalid habit name.");

    const habitRef = doc(db, `users/${userId}/habits`, habitId);
    const newIndexRef = doc(db, `users/${userId}/habitNameIndex`, newCanon);

    await runTransaction(db, async (transaction) => {
        const habitSnap = await transaction.get(habitRef);
        if (!habitSnap.exists()) throw new Error("Habit not found.");

        const data = habitSnap.data() as FirestoreHabit;
        const oldCanon = data.canonicalName;

        if (oldCanon === newCanon) {
            transaction.update(habitRef, { name: newName, updatedAt: serverTimestamp() });
            return;
        }

        const newIndexSnap = await transaction.get(newIndexRef);
        if (newIndexSnap.exists()) throw new Error(`Habit "${newName}" already exists.`);

        transaction.delete(doc(db, `users/${userId}/habitNameIndex`, oldCanon));
        transaction.set(newIndexRef, { habitId, createdAt: serverTimestamp() });
        transaction.update(habitRef, { 
            name: newName, 
            canonicalName: newCanon, 
            updatedAt: serverTimestamp() 
        });
    });
};

// 4. Archive Habit
export const archiveHabit = async (userId: string, habitId: string) => {
    const ref = doc(db, `users/${userId}/habits`, habitId);
    await updateDoc(ref, { 
        status: 'archived',
        inactiveFrom: getTodayStr(),
        updatedAt: serverTimestamp()
    });
};

// 5. Reorder
export const reorderUserHabits = async (userId: string, orderedHabits: { id: string }[]) => {
    const batch = writeBatch(db);
    orderedHabits.forEach((h, index) => {
        const ref = doc(db, `users/${userId}/habits`, h.id);
        batch.update(ref, { sortOrder: index });
    });
    await batch.commit();
};

// 6. Commit Onboarding (Updated)
export const commitOnboarding = async (
    userId: string, 
    habitNames: string[],
    email: string
) => {
    const userRef = doc(db, 'users', userId);
    const todayStr = getTodayStr();

    // Init current week
    const parts = todayStr.split('-');
    const localDate = new Date(parseInt(parts[0]), parseInt(parts[1])-1, parseInt(parts[2]));
    const { year, weekId } = getWeekParams(localDate);

    const weekRef = doc(db, `users/${userId}/${year}/${weekId}`);

    await runTransaction(db, async (transaction) => {
        const userSnap = await transaction.get(userRef);
        if (userSnap.exists() && userSnap.data().isOnboarded) return;

        const uniqueNames = new Set<string>();
        const processedHabits: { name: string, canon: string, ref: DocumentReference, indexRef: DocumentReference }[] = [];

        for (const name of habitNames) {
            const canon = getCanonicalName(name);
            if (!canon || uniqueNames.has(canon)) continue;
            uniqueNames.add(canon);

            const habitRef = doc(collection(db, `users/${userId}/habits`));
            const indexRef = doc(db, `users/${userId}/habitNameIndex`, canon);
            processedHabits.push({ name, canon, ref: habitRef, indexRef });
        }

        transaction.set(userRef, {
            isOnboarded: true,
            theme: 'dark',
            userName: email, // Default to email
            motto: null,
            isAdmin: false,
            createdAt: userSnap.exists() ? userSnap.data().createdAt : serverTimestamp(),
            onboardedAt: serverTimestamp()
        }, { merge: true });

        // Initialize Week Doc
        transaction.set(weekRef, {
            updatedAt: serverTimestamp()
        }, { merge: true });

        processedHabits.forEach((h, index) => {
            transaction.set(h.indexRef, { habitId: h.ref.id, createdAt: serverTimestamp() });
            transaction.set(h.ref, {
                name: h.name,
                canonicalName: h.canon,
                status: 'active',
                activeFrom: todayStr,
                inactiveFrom: null,
                sortOrder: index,
                createdAt: serverTimestamp(),
                updatedAt: serverTimestamp()
            });
        });
    });
};

// 7. Update User Profile
export const updateUserProfile = async (userId: string, data: { userName?: string, motto?: string }) => {
    const ref = doc(db, 'users', userId);
    await updateDoc(ref, {
        ...data,
        updatedAt: serverTimestamp()
    });
};

// 8. Delete User
export const deleteUserAccount = async (userId: string) => {
    const years = [new Date().getFullYear(), new Date().getFullYear() - 1];
    const subColls = ['habits', 'habitNameIndex'];

    // Clean Habits
    for (const col of subColls) {
        const snap = await getDocs(collection(db, `users/${userId}/${col}`));
        const batch = writeBatch(db);
        snap.forEach(d => batch.delete(d.ref));
        await batch.commit();
    }

    // Clean Weeks
    for (const y of years) {
         const snap = await getDocs(collection(db, `users/${userId}/${y}`));
         const batch = writeBatch(db);
         snap.forEach(d => batch.delete(d.ref));
         await batch.commit();
    }

    await deleteDoc(doc(db, 'users', userId));
    if (auth.currentUser) await deleteUser(auth.currentUser);
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    commitOnboarding,
    getWeekParams,
    getWeekRange,
    updateUserProfile,
    toLocalISOString
} from '../lib/firestore';

interface UserSettings {
    theme: ThemeOption;
    isOnboarded: boolean;
    userName: string;
    motto: string;
    isAdmin: boolean;
}

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  updateProfile: (data: { userName?: string, motto?: string }) => Promise<void>;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  dataYear: new Date().getFullYear(),
  userName: '',
  motto: '',
  isAdmin: false,
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [userSettings, setUserSettings] = useState<UserSettings | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const today = new Date();
    // CRITICAL: Use the year from getWeekParams to ensure we listen to the correct collection
    const { year: currentWeekYear } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs (Listen to the Calculated Year Collection)
    const yearCollection = collection(db, `users/${userId}/${currentWeekYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // Reconstruct Logs from strict Week Ranges
            const weekNum = parseInt(weekId.replace('week', ''));
            const { start, end } = getWeekRange(parseInt(currentWeekYear), weekNum);

            // Iterate from start to end of that week
            const current = new Date(start);
            while (current <= end) {
                const dayName = current.toLocaleDateString('en-US', { weekday: 'short' }).toLowerCase();
                const habitIds = data[dayName];

                if (Array.isArray(habitIds) && habitIds.length > 0) {
                    const dateStr = toLocalISOString(current);
                    const checks: Record<string, boolean> = {};
                    habitIds.forEach((hid: string) => checks[hid] = true);

                    allLogs.push({
                        date: dateStr,
                        weekId,
                        checks
                    });
                }

                current.setDate(current.getDate() + 1);
            }
        });

        setLogs(allLogs);
    });

    // C. User Settings (and Profile)
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false,
                userName: data.userName || user.email || 'User',
                motto: data.motto || '',
                isAdmin: data.isAdmin || false
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      await toggleHabitCompletion(user.uid, habitId, date);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      const habit = habits.find(h => h.id === id);
      if (habit) {
          await createHabit(user.uid, habit.name);
      }
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      await commitOnboarding(user.uid, habitNames, user.email || 'User');
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const updateProfileAction = async (data: { userName?: string, motto?: string }) => {
      if (!user) return;
      await updateUserProfile(user.uid, data);
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      dataYear: new Date().getFullYear(),
      userName: userSettings?.userName || '',
      motto: userSettings?.motto || '',
      isAdmin: userSettings?.isAdmin || false
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      updateProfile: updateProfileAction,
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ChevronLeft, ChevronRight } from 'lucide-react';

type ViewMode = 'Year' | 'Month' | 'Week';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [view, setView] = useState<ViewMode>('Year');

  // Navigation States
  const [selectedWeekOffset, setSelectedWeekOffset] = useState(0); 
  const [selectedMonthOffset, setSelectedMonthOffset] = useState(0); 

  const today = new Date();
  const currentYear = today.getFullYear();
  const todayStr = today.toISOString().split('T')[0];

  // Helper: Is habit applicable on date?
  const isApplicable = (habitId: string, dateStr: string) => {
      const habit = state.habits.find(h => h.id === habitId);
      if (!habit) return false;
      return dateStr >= habit.activeFrom && (!habit.inactiveFrom || dateStr < habit.inactiveFrom);
  };

  const getWeekNumber = (d: Date) => {
      const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
      date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
      const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const weekNo = Math.ceil(( ( (date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
      return weekNo - 1; 
  };

  const currentWeekIndex = getWeekNumber(today);

  // --- VIEW: YEAR ---
  const renderYearView = () => {
    const weeks = [];
    let d = new Date(currentYear, 0, 1);

    // Adjust to start of week (Sunday)
    while (d.getDay() !== 0) {
        d.setDate(d.getDate() - 1);
    }

    for (let i = 0; i < 53; i++) {
        const weekStart = new Date(d);
        const weekEnd = new Date(d);
        weekEnd.setDate(weekEnd.getDate() + 6);

        const startStr = weekStart.toISOString().split('T')[0];
        const endStr = weekEnd.toISOString().split('T')[0];

        // Compute "Days Logged" (Any activity on that day)
        const logsInWeek = state.logs.filter(l => l.date >= startStr && l.date <= endStr);
        const activeDays = logsInWeek.filter(l => Object.keys(l.checks || {}).length > 0).length;

        const fillPercent = (activeDays / 7) * 100;

        weeks.push({ 
            id: i, 
            fillPercent, 
            startDate: weekStart,
            isCurrent: i === currentWeekIndex,
            isFuture: i > currentWeekIndex,
            weekNum: i + 1
        });

        d.setDate(d.getDate() + 7);
    }

    return (
        <div className="grid grid-cols-7 gap-3 px-2">
            {weeks.map((w) => (
                <button
                    key={w.id}
                    disabled={w.isFuture}
                    onClick={() => {
                        const offset = w.id - currentWeekIndex;
                        setSelectedWeekOffset(offset);
                        setView('Week');
                    }}
                    className={`aspect-square rounded-md border relative overflow-hidden flex items-end justify-center transition-all
                        ${w.isFuture 
                             ? 'border-gray-100 dark:border-gray-800 opacity-20 cursor-default' 
                             : 'border-gray-200 dark:border-gray-800 cursor-pointer hover:border-ledger-accent'
                        }
                        ${w.isCurrent ? 'ring-2 ring-ledger-accent ring-offset-2 dark:ring-offset-ledger-bgDark' : ''}
                    `}
                >
                    {!w.isFuture && (
                        <div 
                            className="absolute inset-x-0 bottom-0 bg-ledger-accent transition-all duration-700 ease-out opacity-80"
                            style={{ height: `${Math.max(w.fillPercent, 0)}%` }}
                        />
                    )}
                    <span className="relative z-10 text-[10px] font-bold text-ledger-text dark:text-ledger-textDark mix-blend-difference mb-1">
                        {w.weekNum}
                    </span>
                </button>
            ))}
        </div>
    );
  };

  // --- VIEW: MONTH ---
  const renderMonthView = () => {
    const targetDate = new Date(today.getFullYear(), today.getMonth() + selectedMonthOffset, 1);
    const targetMonth = targetDate.getMonth();
    const targetYear = targetDate.getFullYear();

    const minOffset = -today.getMonth();
    const maxOffset = 11 - today.getMonth();
    const isPrevDisabled = selectedMonthOffset <= minOffset;
    const isNextDisabled = selectedMonthOffset >= maxOffset;

    const daysInMonth = new Date(targetYear, targetMonth + 1, 0).getDate();
    const firstDayIndex = new Date(targetYear, targetMonth, 1).getDay();

    const days = Array.from({ length: daysInMonth }, (_, i) => {
        const d = new Date(targetYear, targetMonth, i + 1);
        const dateStr = d.toISOString().split('T')[0];
        const log = state.logs.find(l => l.date === dateStr);
        const hasLog = log && Object.keys(log.checks || {}).length > 0;
        const isToday = dateStr === todayStr;
        return { dateStr, dayNum: i + 1, hasLog, isToday };
    });

    const blanks = Array.from({ length: firstDayIndex }, (_, i) => i);

    return (
        <div className="px-4">
             {/* Header Controls */}
             <div className="flex items-center justify-between mb-6 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p - 1)} 
                    disabled={isPrevDisabled}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark uppercase tracking-wide">
                      {targetDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p + 1)} 
                    disabled={isNextDisabled} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

             <div className="grid grid-cols-7 gap-3">
                {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="text-center text-[10px] font-bold text-ledger-muted uppercase mb-2">{d}</div>
                ))}

                {blanks.map(i => <div key={`blank-${i}`} />)}

                {days.map(d => {
                    // Logic for styles
                    let className = "aspect-square rounded-lg flex items-center justify-center text-sm font-semibold transition-all relative ";

                    if (d.isToday) {
                        // NEW TODAY DESIGN: Bordered.
                        if (d.hasLog) {
                            // Filled + Strong Border
                            className += "bg-ledger-accent text-white shadow-sm border-2 border-ledger-text dark:border-white";
                        } else {
                            // Empty + Accent Border + Accent Text
                            className += "bg-transparent text-ledger-accent border-2 border-ledger-accent";
                        }
                    } else {
                        // Normal Days
                        if (d.hasLog) {
                             className += "bg-ledger-accent text-white shadow-sm";
                        } else {
                             className += "bg-white dark:bg-ledger-surfaceDark text-ledger-muted border border-gray-100 dark:border-gray-800";
                        }
                    }

                    return (
                        <div key={d.dateStr} className={className}>
                            {d.dayNum}
                            {d.isToday && !d.hasLog && (
                                <div className="absolute -bottom-1 w-1 h-1 bg-ledger-accent rounded-full" />
                            )}
                        </div>
                    );
                })}
             </div>
        </div>
    );
  };

  // --- VIEW: WEEK ---
  const renderWeekView = () => {
      // Logic: x is SUN to SAT.
      // 1. Determine the Sunday of the selected week offset.
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay(); // 0 is Sunday
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff); // This is Sunday

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];

          let possible = 0;
          let completed = 0;

          // Check logs vs active habits
          state.habits.forEach(h => {
              if (isApplicable(h.id, dateStr)) {
                  possible++;
                  const log = state.logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      completed++;
                  }
              }
          });

          // y = checked / total (possible)
          const pct = possible > 0 ? (completed / possible) * 100 : 0;
          const isDifferentYear = d.getFullYear() !== currentYear;
          const isToday = dateStr === todayStr;

          // Hardcoded Sun-Sat labels for consistency with axis request
          const label = ['S','M','T','W','T','F','S'][i];

          return { 
              label, 
              pct, 
              dateStr,
              isDifferentYear,
              isToday,
              possible // Debug/Logic check
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      const isEarliestWeek = selectedWeekOffset <= -currentWeekIndex;

      return (
          <div className="px-4">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p - 1)} 
                    disabled={isEarliestWeek}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p + 1)} 
                    disabled={selectedWeekOffset >= 0} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
