import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    restoreUserHabit,
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    commitOnboarding,
    getWeekParams,
    getWeekRange,
    updateUserProfile,
    toLocalISOString,
    updateAppStreak
} from '../lib/firestore';

interface UserSettings {
    theme: ThemeOption;
    isOnboarded: boolean;
    userName: string;
    motto: string;
    isAdmin: boolean;
    // New Fields
    alertTimes: string[] | null;
    isRanked: boolean;
    isActive: boolean;
    deleteTime: string | null;
    dayStreak: number;
    timeZone: string;
}

interface AppContextType {
  state: AppState;
  streakNotification: { visible: boolean, days: number } | null;
  dismissStreakNotification: () => void;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  updateProfile: (data: { userName?: string, motto?: string, alertTimes?: string[] | null }) => Promise<void>;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  weeklyStats: {},
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  dataYear: new Date().getFullYear(),
  userName: '',
  motto: '',
  isAdmin: false,
  alertTimes: null,
  isRanked: true, // Default to true
  isActive: true,
  deleteTime: null,
  dayStreak: 0,
  timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [streakNotification, setStreakNotification] = useState<{ visible: boolean, days: number } | null>(null);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [weeklyStats, setWeeklyStats] = useState<Record<string, number>>({});
  const [userSettings, setUserSettings] = useState<UserSettings | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setWeeklyStats({});
        setUserSettings(null);
        setIsLoading(false);
        setStreakNotification(null);
      } else {
         // Check streak on login/load
         // We do this once here, not inside onSnapshot to avoid loops
         updateAppStreak(u.uid).then((res) => {
             if (res && res.showedAnimation) {
                 setStreakNotification({ visible: true, days: res.streak });
             }
         });
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const today = new Date();
    // CRITICAL: Use the year from getWeekParams to ensure we listen to the correct collection
    const { year: currentWeekYear } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs & Weekly Stats (Listen to the Calculated Year Collection)
    const yearCollection = collection(db, `users/${userId}/${currentWeekYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];
        let stats: Record<string, number> = {};

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // 1. Capture Weekly Percent
            if (typeof data.lastPercent === 'number') {
                stats[weekId] = data.lastPercent;
            }

            // 2. Reconstruct Logs from strict Week Ranges
            const weekNum = parseInt(weekId.replace('week', ''));
            const { start, end } = getWeekRange(parseInt(currentWeekYear), weekNum);

            // Iterate from start to end of that week
            const current = new Date(start);
            while (current <= end) {
                const dayName = current.toLocaleDateString('en-US', { weekday: 'short' }).toLowerCase();
                const habitIds = data[dayName];

                if (Array.isArray(habitIds) && habitIds.length > 0) {
                    const dateStr = toLocalISOString(current);
                    const checks: Record<string, boolean> = {};
                    habitIds.forEach((hid: string) => checks[hid] = true);

                    allLogs.push({
                        date: dateStr,
                        weekId,
                        checks
                    });
                }

                current.setDate(current.getDate() + 1);
            }
        });

        setLogs(allLogs);
        setWeeklyStats(stats);
    });

    // C. User Settings (and Profile)
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false,
                userName: data.userName || user.email || 'User',
                motto: data.motto || '',
                isAdmin: data.isAdmin || false,
                // Map New Fields
                alertTimes: data.alertTimes || null,
                isRanked: data.isRanked !== undefined ? data.isRanked : true, // Handle undefined as true
                isActive: data.isActive !== undefined ? data.isActive : true,
                deleteTime: data.deleteTime || null,
                dayStreak: data.dayStreak || 0,
                timeZone: data.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const dismissStreakNotification = () => {
      setStreakNotification(null);
  };

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      // Pass the count of currently active habits to update the week's lastPercent
      const activeCount = habits.filter(h => h.status === 'active').length;
      await toggleHabitCompletion(user.uid, habitId, date, activeCount);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      await restoreUserHabit(user.uid, id);
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      await commitOnboarding(user.uid, habitNames, user.email || 'User');
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const updateProfileAction = async (data: { userName?: string, motto?: string, alertTimes?: string[] | null }) => {
      if (!user) return;
      await updateUserProfile(user.uid, data);
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      weeklyStats,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      dataYear: new Date().getFullYear(),
      userName: userSettings?.userName || '',
      motto: userSettings?.motto || '',
      isAdmin: userSettings?.isAdmin || false,
      alertTimes: userSettings?.alertTimes || null,
      isRanked: userSettings?.isRanked !== undefined ? userSettings?.isRanked : true,
      isActive: userSettings?.isActive !== undefined ? userSettings?.isActive : true,
      deleteTime: userSettings?.deleteTime || null,
      dayStreak: userSettings?.dayStreak || 0,
      timeZone: userSettings?.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      streakNotification,
      dismissStreakNotification,
      addHabit, 
      toggleHabit, 
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      updateProfile: updateProfileAction,
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ChevronLeft, Flame, Crown, Medal } from 'lucide-react';
import { getLeaderboard, LeaderboardEntry } from '../lib/firestore';
import { useApp } from '../context/AppContext';
import { auth } from '../lib/firebase';

export const Leaderboard: React.FC = () => {
  const navigate = useNavigate();
  const { state } = useApp(); // Access global state if needed for theme, etc.
  const [entries, setEntries] = useState<LeaderboardEntry[]>([]);
  const [loading, setLoading] = useState(true);

  // Get current user ID synchronously for UI highlighting
  const currentUserId = auth.currentUser?.uid;

  useEffect(() => {
    const fetch = async () => {
        const data = await getLeaderboard();
        setEntries(data);
        setLoading(false);
    };
    fetch();
  }, []);

  const getRankIcon = (rank: number) => {
      // 1st Place: Gold Crown
      if (rank === 1) return <Crown size={24} className="text-yellow-500 fill-yellow-500 drop-shadow-sm" />;

      // 2nd Place: Silver Medal
      if (rank === 2) return <Medal size={22} className="text-slate-400 fill-slate-400" />;

      // 3rd Place: Bronze Medal
      if (rank === 3) return <Medal size={22} className="text-amber-700 fill-amber-700" />;

      // 4th - 10th Place: Indigo (Top 10)
      if (rank <= 10) return <span className="text-sm font-bold text-indigo-500 dark:text-indigo-400 font-mono w-6 text-center">{rank}</span>;

      // 11th - 50th Place: Muted (Standard)
      return <span className="text-sm font-bold text-ledger-muted font-mono w-6 text-center">{rank}</span>;
  };

  return (
    <div className="h-full flex flex-col bg-ledger-bg dark:bg-ledger-bgDark">
      <header className="px-6 py-5 flex items-center gap-4 border-b border-ledger-border dark:border-ledger-borderDark bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-xl sticky top-0 z-50">
        <button onClick={() => navigate('/today')} className="p-2 -ml-2 text-ledger-muted hover:text-ledger-text dark:hover:text-white transition-colors">
            <ChevronLeft size={24} />
        </button>
        <div>
            <h1 className="text-xl font-bold text-ledger-text dark:text-ledger-textDark tracking-tight">Hall of Fame</h1>
            <p className="text-xs text-ledger-muted">Top streaks worldwide</p>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto no-scrollbar p-4">
          {loading ? (
              <div className="flex flex-col items-center justify-center h-64 opacity-50">
                  <div className="w-8 h-8 border-2 border-ledger-accent border-t-transparent rounded-full animate-spin mb-4" />
                  <p className="text-xs text-ledger-muted">Loading rankings...</p>
              </div>
          ) : entries.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-ledger-muted">
                  <p>No ranked users found.</p>
              </div>
          ) : (
              <div className="space-y-3 pb-12">
                  {entries.map((entry, index) => {
                      const rank = index + 1;
                      const isCurrentUser = entry.id === currentUserId;

                      return (
                        <div 
                            key={entry.id}
                            className={`flex items-center p-4 rounded-xl border transition-all animate-fade-in
                                ${isCurrentUser 
                                    ? 'bg-ledger-accent/5 border-ledger-accent shadow-sm' 
                                    : 'bg-white dark:bg-ledger-surfaceDark border-ledger-border dark:border-ledger-borderDark'
                                }
                            `}
                            style={{ animationDelay: `${index * 0.05}s` }}
                        >
                            <div className="flex items-center justify-center w-10 mr-3">
                                {getRankIcon(rank)}
                            </div>

                            <div className="flex-1 min-w-0 mr-4">
                                <h3 className={`font-bold text-sm truncate ${isCurrentUser ? 'text-ledger-accent' : 'text-ledger-text dark:text-ledger-textDark'}`}>
                                    {entry.userName} {isCurrentUser && <span className="text-[10px] bg-ledger-accent text-white px-1.5 py-0.5 rounded-md ml-1 align-middle">YOU</span>}
                                </h3>
                                {entry.motto && (
                                    <p className="text-xs text-ledger-muted opacity-80 mt-0.5 line-clamp-2 leading-tight">
                                        "{entry.motto}"
                                    </p>
                                )}
                            </div>

                            <div className="flex items-center gap-1.5 bg-gray-50 dark:bg-white/5 px-2.5 py-1.5 rounded-lg shrink-0">
                                <span className="font-mono font-bold text-ledger-text dark:text-ledger-textDark text-sm">
                                    {entry.dayStreak}
                                </span>
                                <Flame size={14} className="text-orange-500 fill-orange-500" />
                            </div>
                        </div>
                      );
                  })}
              </div>
          )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { ChevronLeft, ChevronRight, Check } from 'lucide-react';
import { toLocalISOString, getWeekParams, getWeekRange } from '../lib/firestore';

type ViewMode = 'Year' | 'Month' | 'Week';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [view, setView] = useState<ViewMode>('Year');

  // Navigation States
  const [selectedWeekOffset, setSelectedWeekOffset] = useState(0); 

  // Scroll Refs
  const monthRefs = useRef<(HTMLDivElement | null)[]>([]);

  const today = new Date();
  const currentYear = today.getFullYear();
  const currentMonthIndex = today.getMonth();
  const todayStr = toLocalISOString(today);

  // Helper: Is habit applicable on date?
  const isApplicable = (habitId: string, dateStr: string) => {
      const habit = state.habits.find(h => h.id === habitId);
      if (!habit) return false;
      return dateStr >= habit.activeFrom && (!habit.inactiveFrom || dateStr < habit.inactiveFrom);
  };

  // Generate Year Grid Data strictly
  const generateYearGrid = () => {
      const weeks = [];
      let d = new Date(currentYear, 0, 1);

      // Align to start of week (Sunday)
      while (d.getDay() !== 0) {
          d.setDate(d.getDate() - 1);
      }

      let currentWeekIdx = -1;

      // Generate 53 weeks to cover year boundaries safely
      for (let i = 0; i < 53; i++) {
          const weekStart = new Date(d);
          const weekEnd = new Date(d);
          weekEnd.setDate(weekEnd.getDate() + 6);

          const sStr = toLocalISOString(weekStart);
          const eStr = toLocalISOString(weekEnd);

          const isCurrent = todayStr >= sStr && todayStr <= eStr;
          if (isCurrent) currentWeekIdx = i;

          const weekId = `week${i + 1}`;
          const fillPercent = state.weeklyStats[weekId] || 0;

          weeks.push({
              id: i,
              fillPercent,
              startDate: weekStart,
              endDate: weekEnd,
              isCurrent,
              weekNum: i + 1,
              // Temporarily mark future until we know currentWeekIdx
              isFuture: false 
          });

          d.setDate(d.getDate() + 7);
      }

      // Post-process for isFuture using the found current index
      return { 
          weeks: weeks.map(w => ({
              ...w,
              isFuture: currentWeekIdx !== -1 && w.id > currentWeekIdx
          })), 
          currentWeekIdx 
      };
  };

  const { weeks: yearWeeks, currentWeekIdx } = generateYearGrid();

  // Auto-scroll effect
  useEffect(() => {
    if (view === 'Month' && monthRefs.current[currentMonthIndex]) {
        // Small delay to ensure layout is painted
        setTimeout(() => {
            monthRefs.current[currentMonthIndex]?.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }, 50);
    }
  }, [view, currentMonthIndex]);

  // --- VIEW: YEAR ---
  const renderYearView = () => {
    return (
        <div className="grid grid-cols-7 gap-3 px-2">
            {yearWeeks.map((w) => (
                <button
                    key={w.id}
                    disabled={w.isFuture}
                    onClick={() => {
                        // Calculate offset relative to the actual current week index
                        const offset = w.id - currentWeekIdx;
                        setSelectedWeekOffset(offset);
                        setView('Week');
                    }}
                    className={`aspect-square rounded-md border relative overflow-hidden flex items-end justify-center transition-all
                        ${w.isFuture 
                             ? 'border-gray-100 dark:border-gray-800 opacity-20 cursor-default' 
                             : 'border-gray-200 dark:border-gray-800 cursor-pointer hover:border-ledger-accent'
                        }
                        ${w.isCurrent ? 'ring-2 ring-ledger-accent ring-offset-2 dark:ring-offset-ledger-bgDark' : ''}
                    `}
                >
                    {!w.isFuture && (
                        <div 
                            className="absolute inset-x-0 bottom-0 bg-ledger-accent transition-all duration-700 ease-out opacity-80"
                            style={{ height: `${Math.max(w.fillPercent, 0)}%` }}
                        />
                    )}
                    <span className="relative z-10 text-[10px] font-bold text-ledger-text dark:text-ledger-textDark mix-blend-difference mb-1">
                        {w.weekNum}
                    </span>
                </button>
            ))}
        </div>
    );
  };

  // --- VIEW: MONTH ---
  const renderMonthView = () => {
    // Render all 12 months in a scrollable list
    const months = Array.from({ length: 12 }, (_, i) => i);

    return (
        <div className="h-full flex flex-col -mt-2">
             {/* Sticky Headers for Days */}
             <div className="grid grid-cols-7 gap-3 px-4 py-3 bg-ledger-bg dark:bg-ledger-bgDark z-10 border-b border-gray-100 dark:border-gray-800">
                {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="text-center text-[10px] font-bold text-ledger-muted uppercase">{d}</div>
                ))}
            </div>

             <div className="overflow-y-auto flex-1 px-4 pb-20 no-scrollbar">
                {months.map(monthIndex => {
                    const daysInMonth = new Date(currentYear, monthIndex + 1, 0).getDate();
                    const firstDayIndex = new Date(currentYear, monthIndex, 1).getDay(); // 0-6
                    const monthName = new Date(currentYear, monthIndex, 1).toLocaleDateString('en-US', { month: 'long' });

                    const days = Array.from({ length: daysInMonth }, (_, i) => {
                        const d = new Date(currentYear, monthIndex, i + 1);
                        const dateStr = toLocalISOString(d);
                        const hasLog = !!state.logs.find(l => l.date === dateStr);
                        const isToday = dateStr === todayStr;
                        return { dateStr, dayNum: i + 1, hasLog, isToday, dateObj: d };
                    });

                    const blanks = Array.from({ length: firstDayIndex }, (_, i) => i);

                    return (
                        <div 
                            key={monthIndex} 
                            ref={el => { monthRefs.current[monthIndex] = el }}
                            className="pt-6 pb-2"
                        >
                            <h3 className="text-sm font-bold text-ledger-text dark:text-ledger-textDark mb-4 sticky top-0 bg-ledger-bg dark:bg-ledger-bgDark py-1 z-0 inline-block px-1 rounded-md">
                                {monthName}
                            </h3>
                            <div className="grid grid-cols-7 gap-3">
                                {blanks.map(i => <div key={`blank-${i}`} />)}

                                {days.map(d => {
                                    const isFuture = d.dateStr > todayStr;
                                    const isBeforeYearStart = d.dateStr < `${currentYear}-01-01`; 
                                    const isDisabled = isFuture || isBeforeYearStart;

                                    let className = "aspect-square rounded-lg flex items-center justify-center text-sm font-semibold transition-all relative ";

                                    if (d.isToday) {
                                        if (d.hasLog) {
                                            className += "bg-ledger-accent text-white shadow-sm border-2 border-ledger-text dark:border-white";
                                        } else {
                                            className += "bg-transparent text-ledger-accent border-2 border-ledger-accent";
                                        }
                                    } else {
                                        if (d.hasLog) {
                                             className += "bg-ledger-accent text-white shadow-sm";
                                        } else {
                                             className += "bg-white dark:bg-ledger-surfaceDark text-ledger-muted border border-gray-100 dark:border-gray-800";
                                        }
                                    }

                                    if (isDisabled) {
                                        className += " opacity-30 cursor-not-allowed";
                                    } else {
                                        className += " cursor-pointer hover:scale-105 active:scale-95";
                                    }

                                    return (
                                        <button 
                                            key={d.dateStr} 
                                            className={className}
                                            disabled={isDisabled}
                                            onClick={() => {
                                                // Jump to Week
                                                const t = new Date(d.dateObj);
                                                const c = new Date(today);

                                                // Align to Sundays
                                                t.setDate(t.getDate() - t.getDay());
                                                c.setDate(c.getDate() - c.getDay());

                                                t.setHours(0,0,0,0);
                                                c.setHours(0,0,0,0);

                                                const diff = t.getTime() - c.getTime();
                                                const weeks = Math.round(diff / (1000 * 60 * 60 * 24 * 7));

                                                setSelectedWeekOffset(weeks);
                                                setView('Week');
                                            }}
                                        >
                                            {d.dayNum}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
             </div>
        </div>
    );
  };

  // --- VIEW: WEEK ---
  const renderWeekView = () => {
      // Logic: x is SUN to SAT.
      // 1. Determine the Sunday of the selected week offset.
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay(); // 0 is Sunday
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff); // This is Sunday

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = toLocalISOString(d);

          // 1. Get Checks for this day
          const log = state.logs.find(l => l.date === dateStr);
          const completedCount = log?.checks ? Object.keys(log.checks).length : 0;

          // 2. Determine Denominator (Total Possible)
          let dailyPossible = 0;

          // Use User's Reverse Logic: lastPercent -> Total Possible -> Daily Possible
          const { weekId, year } = getWeekParams(d);
          const lastPercent = state.weeklyStats[weekId];

          if (typeof lastPercent === 'number' && lastPercent > 0) {
             // Calculate Total Checks in this Week
             const checksInWeek = state.logs
                .filter(l => l.weekId === weekId)
                .reduce((sum, l) => sum + Object.keys(l.checks || {}).length, 0);

             // impliedTotalPossibleForWeek = (checksInWeek / lastPercent) * 100
             const impliedTotalPossibleForWeek = (checksInWeek / lastPercent) * 100;

             // Get days in this specific week (handle partial weeks at year start)
             const { start, end } = getWeekRange(parseInt(year), parseInt(weekId.replace('week','')));
             const daysInThisWeek = Math.floor((end.getTime() - start.getTime()) / (1000 * 3600 * 24)) + 1;

             // Daily possible is the implied total divided by number of days in that week
             dailyPossible = Math.round(impliedTotalPossibleForWeek / daysInThisWeek);
          }

          // Fallback if logic fails (e.g. lastPercent is 0 or missing, or not loaded)
          if (!dailyPossible || dailyPossible === 0) {
              state.habits.forEach(h => {
                  if (isApplicable(h.id, dateStr)) {
                      dailyPossible++;
                  }
              });
          }

          // y = checked / total (possible)
          const pct = dailyPossible > 0 ? (completedCount / dailyPossible) * 100 : 0;
          const isDifferentYear = d.getFullYear() !== currentYear;
          const isToday = dateStr === todayStr;

          // Hardcoded Sun-Sat labels for consistency with axis request
          const label = ['S','M','T','W','T','F','S'][i];

          return { 
              label, 
              pct, 
              dateStr,
              isDifferentYear,
              isToday,
              possible: dailyPossible
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      const isEarliestWeek = selectedWeekOffset <= -currentWeekIdx; // Correct bound check

      return (
          <div className="px-4 pb-12">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p - 1)} 
                    disabled={isEarliestWeek}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p + 1)} 
                    disabled={selectedWeekOffset >= 0} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
                      <div key={i} className={`flex flex-col items-center gap-2 flex-1 h-full justify-end group ${d.isDifferentYear ? 'opacity-30 grayscale' : ''}`}>
                          {/* Bar */}
                          <div className="w-full bg-gray-100 dark:bg-white/5 rounded-t-sm relative h-full flex items-end overflow-hidden">
                              <div 
                                  className={`w-full bg-ledger-accent transition-all duration-500 ease-out rounded-t-sm ${d.isDifferentYear ? 'bg-gray-400' : ''}`}
                                  style={{ height: `${d.pct}%` }} 
                              />
                          </div>

                          {/* Label (Sun-Sat) */}
                          <div className={`
                             flex items-center justify-center rounded-md px-1.5 py-0.5
                             ${d.isToday 
                                ? 'bg-ledger-accent text-white shadow-sm' 
                                : 'bg-transparent text-ledger-muted'
                             }
                          `}>
                              <span className="text-xs font-bold uppercase">{d.label}</span>
                          </div>
                      </div>
                  ))}
              </div>

              {/* History List */}
              <div className="mt-8 animate-fade-in" style={{ animationDelay: '0.1s' }}>
                  <h3 className="text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4 px-1">Weekly History</h3>
                  <div className="space-y-3">
                      {[...weekDays].reverse().map((d) => {
                          if (d.dateStr > todayStr) return null; // Don't show future days in history log

                          const [y, m, dayNum] = d.dateStr.split('-').map(Number);
                          const dateObj = new Date(y, m - 1, dayNum);
                          const dayName = dateObj.toLocaleDateString('en-US', { weekday: 'long' });
                          const dayDate = dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

                          const log = state.logs.find(l => l.date === d.dateStr);
                          const checks = log?.checks || {};
                          const completedHabitIds = Object.keys(checks);
                          const completedHabits = state.habits.filter(h => completedHabitIds.includes(h.id));

                          return (
                              <div key={d.dateStr} className="bg-white dark:bg-ledger-surfaceDark rounded-xl p-4 border border-ledger-border dark:border-ledger-borderDark shadow-sm">
                                   <div className="flex items-center justify-between mb-3 border-b border-gray-50 dark:border-gray-800 pb-2">
                                      <span className={`text-sm font-bold ${d.isToday ? 'text-ledger-accent' : 'text-ledger-text dark:text-ledger-textDark'}`}>
                                          {dayName}, {dayDate}
                                      </span>
                                      {d.isToday && <span className="text-[10px] font-bold bg-ledger-accent text-white px-2 py-0.5 rounded-full">TODAY</span>}
                                   </div>

                                   {completedHabits.length > 0 ? (
                                       <div className="grid grid-cols-1 gap-2">
                                           {completedHabits.map(h => (
                                               <div key={h.id} className="flex items-center gap-3">
                                                   <div className="w-4 h-4 rounded-full bg-ledger-accent flex items-center justify-center shrink-0">
                                                      <Check size={10} className="text-white" strokeWidth={4} />
                                                   </div>
                                                   <span className="text-sm font-medium text-ledger-text dark:text-ledger-textDark">{h.name}</span>
                                               </div>
                                           ))}
                                       </div>
                                   ) : (
                                       <p className="text-xs text-ledger-muted italic pl-1">No completed tasks.</p>
                                   )}
                              </div>
                          );
                      })}
                  </div>
              </div>
          </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-4 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark px-2">Progress</h1>
      </header>

      {/* View Switcher */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-xl mb-6 mx-2 shrink-0">
          {(['Year', 'Month', 'Week'] as ViewMode[]).map(mode => (
              <button 
                key={mode}
                onClick={() => {
                    setView(mode);
                    if(mode === 'Week') setSelectedWeekOffset(0);
                }}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wide rounded-lg transition-all ${view === mode ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {mode}
              </button>
          ))}
      </div>

      <div className="flex-1 animate-fade-in overflow-hidden">
          {view === 'Year' && (
              <div className="h-full overflow-y-auto no-scrollbar pb-10">
                  <h3 className="px-2 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{currentYear} Overview</h3>
                  {renderYearView()}
              </div>
          )}
          {view === 'Month' && renderMonthView()}
          {view === 'Week' && renderWeekView()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { MAX_HABITS, Habit } from '../types';
import { Archive, ArrowUp, ArrowDown, RotateCcw, Plus, AlertCircle } from 'lucide-react';
import { Button } from '../components/Button';

// Sub-component for individual habit rows to manage focus/error states locally
const HabitItem: React.FC<{
  habit: Habit;
  index: number;
  isFirst: boolean;
  isLast: boolean;
  onUpdate: (id: string, name: string) => Promise<void>;
  onArchive: (id: string) => void;
  onMove: (index: number, direction: 'up' | 'down') => void;
}> = ({ habit, index, isFirst, isLast, onUpdate, onArchive, onMove }) => {
  const [name, setName] = useState(habit.name);
  const [error, setError] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  useEffect(() => {
      setName(habit.name);
  }, [habit.name]);

  const handleBlur = async () => {
      setIsFocused(false);
      const trimmed = name.trim();
      if (trimmed === habit.name) {
          setError('');
          return;
      }

      if (!trimmed) {
          setName(habit.name); // Revert if empty
          return;
      }

      try {
          setError('');
          await onUpdate(habit.id, trimmed);
      } catch (e: any) {
          // Revert visual to original if error (or keep dirty and show error)
          // Choosing to show error and keep dirty value so user can fix
          if (e.message.includes('already exists')) {
              setError('Name taken');
          } else {
              setError('Error');
          }
      }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
          e.currentTarget.blur();
      }
  };

  return (
    <div className={`bg-white dark:bg-ledger-surfaceDark p-4 rounded-xl shadow-sm border transition-all group relative ${error ? 'border-red-500' : 'border-ledger-border dark:border-ledger-borderDark hover:border-ledger-accent/50'}`}>
        <div className="flex items-center gap-3">
            <div className="flex flex-col gap-0.5 text-ledger-muted opacity-30 group-hover:opacity-100 transition-opacity">
                <button 
                    onClick={() => onMove(index, 'up')}
                    disabled={isFirst}
                    className="hover:text-ledger-accent disabled:opacity-20"
                >
                    <ArrowUp size={12} />
                </button>
                <button 
                    onClick={() => onMove(index, 'down')}
                    disabled={isLast}
                    className="hover:text-ledger-accent disabled:opacity-20"
                >
                    <ArrowDown size={12} />
                </button>
            </div>

            <div className="flex-1 relative">
                <input 
                    className={`w-full bg-transparent font-semibold text-lg focus:outline-none focus:text-ledger-accent placeholder-ledger-muted/50 ${error ? 'text-red-500' : 'text-ledger-text dark:text-ledger-textDark'}`}
                    value={name}
                    onChange={(e) => {
                        setName(e.target.value);
                        setError('');
                    }}
                    onFocus={() => setIsFocused(true)}
                    onBlur={handleBlur}
                    onKeyDown={handleKeyDown}
                    maxLength={17}
                />
            </div>

            <div className="flex items-center pl-4 border-l border-gray-100 dark:border-gray-800 ml-2">
                <button 
                    onClick={() => onArchive(habit.id)}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-lg text-ledger-muted hover:text-red-500 transition-colors"
                    title="Archive"
                >
                    <Archive size={18} />
                </button>
            </div>
        </div>

        {/* Footer Info: Error or Char Count */}
        {(isFocused || error) && (
            <div className="absolute bottom-1 right-4 flex items-center gap-2 pointer-events-none">
                {error && (
                    <span className="text-[10px] font-bold text-red-500 bg-red-50 dark:bg-red-900/20 px-1.5 rounded flex items-center gap-1">
                        <AlertCircle size={10} /> {error}
                    </span>
                )}
                {isFocused && (
                    <span className={`text-[10px] font-bold tracking-wider ${name.length >= 17 ? 'text-red-500' : 'text-ledger-muted/60'}`}>
                        {name.length}/17
                    </span>
                )}
            </div>
        )}
    </div>
  );
};

export const Habits: React.FC = () => {
  const { state, addHabit, updateHabitName, archiveHabit, restoreHabit, reorderHabits } = useApp();
  const [newHabitName, setNewHabitName] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [addError, setAddError] = useState('');

  const activeHabits = state.habits.filter(h => h.status === 'active');
  const archivedHabits = state.habits.filter(h => h.status === 'archived');
  const isLimitReached = activeHabits.length >= MAX_HABITS;

  const handleAdd = async () => {
    if (!newHabitName.trim()) return;
    try {
        setAddError('');
        await addHabit(newHabitName.trim());
        setNewHabitName('');
        setIsAdding(false);
    } catch (e: any) {
        if (e.message && e.message.includes('already exists')) {
            setAddError('Habit name taken (check archive)');
        } else {
            setAddError(e.message || 'Failed to create');
        }
    }
  };

  const handleUpdateNameWrapper = async (id: string, name: string) => {
     await updateHabitName(id, name);
  };

  const handleRestore = async (id: string) => {
      try {
          await restoreHabit(id);
      } catch (e: any) {
          if (e.message && e.message.includes('already exists')) {
              alert("A habit with this name already exists in your active list.");
          } else {
              alert(e.message);
          }
      }
  }

  const moveHabit = (index: number, direction: 'up' | 'down') => {
    const newIndex = direction === 'up' ? index - 1 : index + 1;
    if (newIndex >= 0 && newIndex < activeHabits.length) {
        reorderHabits(index, newIndex);
    }
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-6 overflow-y-auto no-scrollbar">
      <header className="mb-8 flex justify-between items-center">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">Habits</h1>
        <div className="text-[10px] font-bold text-ledger-muted uppercase bg-gray-200 dark:bg-white/10 px-2.5 py-1 rounded-full tracking-wider">
            {activeHabits.length} / {MAX_HABITS}
        </div>
      </header>

      {/* Active List */}
      <div className="space-y-3 mb-8">
        {activeHabits.map((habit, index) => (
            <HabitItem 
                key={habit.id}
                habit={habit}
                index={index}
                isFirst={index === 0}
                isLast={index === activeHabits.length - 1}
                onUpdate={handleUpdateNameWrapper}
                onArchive={archiveHabit}
                onMove={moveHabit}
            />
        ))}

        {isAdding ? (
            <div className={`p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border-2 ${addError ? 'border-red-500' : 'border-ledger-accent'} animate-fade-in shadow-md`}>
                <div className="flex items-center gap-3 mb-1">
                    <input 
                        autoFocus
                        value={newHabitName}
                        onChange={e => {
                            setNewHabitName(e.target.value);
                            if (addError) setAddError('');
                        }}
                        placeholder="New habit name..."
                        className="flex-1 bg-transparent focus:outline-none text-lg font-semibold text-ledger-text dark:text-ledger-textDark placeholder-ledger-muted/50"
                        onKeyDown={e => e.key === 'Enter' && handleAdd()}
                        maxLength={17}
                    />
                    <button onClick={handleAdd} className="text-sm font-bold bg-ledger-accent text-white px-3 py-1.5 rounded-md hover:opacity-90">Save</button>
                </div>
                <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold text-red-500 h-4 flex items-center">
                        {addError && <><AlertCircle size={10} className="mr-1"/> {addError}</>}
                    </span>
                    <span className={`text-[10px] font-bold tracking-wider ${newHabitName.length >= 17 ? 'text-red-500' : 'text-ledger-muted'}`}>
                        {newHabitName.length}/17
                    </span>
                </div>
            </div>
        ) : (
             <Button 
                variant="secondary" 
                fullWidth 
                onClick={() => setIsAdding(true)}
                disabled={isLimitReached}
                className="border-dashed h-14"
            >
                <Plus size={20} className="mr-2 opacity-60" />
                {isLimitReached ? 'Limit reached' : 'Create new habit'}
            </Button>
        )}
      </div>

      {/* Archived Section */}
      {archivedHabits.length > 0 && (
        <div className="mt-auto pt-8 pb-4">
            <h3 className="text-[10px] font-bold uppercase text-ledger-muted tracking-widest mb-4 ml-1">Archived</h3>
            <div className="space-y-2 opacity-80 hover:opacity-100 transition-opacity">
                {archivedHabits.map(habit => (
                    <div key={habit.id} className="flex items-center justify-between p-3 rounded-lg border border-transparent hover:bg-white dark:hover:bg-white/5 transition-colors group">
                        <span className="text-ledger-muted line-through decoration-2 decoration-ledger-muted/30 font-medium">{habit.name}</span>
                        <button 
                            onClick={() => handleRestore(habit.id)}
                            disabled={isLimitReached}
                            className="text-xs font-bold text-ledger-accent hover:bg-ledger-accent/10 px-3 py-1.5 rounded transition-colors disabled:opacity-30 disabled:cursor-not-allowed flex items-center gap-1.5"
                        >
                            <RotateCcw size={12} />
                            RESTORE
                        </button>
                    </div>
                ))}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    restoreUserHabit,
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    commitOnboarding,
    getWeekParams,
    getWeekRange,
    updateUserProfile,
    toLocalISOString,
    updateAppStreak
} from '../lib/firestore';

interface UserSettings {
    theme: ThemeOption;
    isOnboarded: boolean;
    userName: string;
    motto: string;
    isAdmin: boolean;
    // New Fields
    alertTimes: string[] | null;
    isRanked: boolean;
    isActive: boolean;
    deleteTime: string | null;
    dayStreak: number;
    timeZone: string;
}

interface AppContextType {
  state: AppState;
  streakNotification: { visible: boolean, days: number } | null;
  dismissStreakNotification: () => void;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  updateProfile: (data: { userName?: string, motto?: string, alertTimes?: string[] | null, isRanked?: boolean }) => Promise<void>;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  weeklyStats: {},
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  dataYear: new Date().getFullYear(),
  userName: '',
  motto: '',
  isAdmin: false,
  alertTimes: null,
  isRanked: true, // Default to true
  isActive: true,
  deleteTime: null,
  dayStreak: 0,
  timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [streakNotification, setStreakNotification] = useState<{ visible: boolean, days: number } | null>(null);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [weeklyStats, setWeeklyStats] = useState<Record<string, number>>({});
  const [userSettings, setUserSettings] = useState<UserSettings | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setWeeklyStats({});
        setUserSettings(null);
        setIsLoading(false);
        setStreakNotification(null);
      } else {
         // Check streak on login/load
         // We do this once here, not inside onSnapshot to avoid loops
         updateAppStreak(u.uid).then((res) => {
             if (res && res.showedAnimation) {
                 setStreakNotification({ visible: true, days: res.streak });
             }
         });
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const today = new Date();
    // CRITICAL: Use the year from getWeekParams to ensure we listen to the correct collection
    const { year: currentWeekYear } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs & Weekly Stats (Listen to the Calculated Year Collection)
    const yearCollection = collection(db, `users/${userId}/${currentWeekYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];
        let stats: Record<string, number> = {};

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // 1. Capture Weekly Percent
            if (typeof data.lastPercent === 'number') {
                stats[weekId] = data.lastPercent;
            }

            // 2. Reconstruct Logs from strict Week Ranges
            const weekNum = parseInt(weekId.replace('week', ''));
            const { start, end } = getWeekRange(parseInt(currentWeekYear), weekNum);

            // Iterate from start to end of that week
            const current = new Date(start);
            while (current <= end) {
                const dayName = current.toLocaleDateString('en-US', { weekday: 'short' }).toLowerCase();
                const habitIds = data[dayName];

                if (Array.isArray(habitIds) && habitIds.length > 0) {
                    const dateStr = toLocalISOString(current);
                    const checks: Record<string, boolean> = {};
                    habitIds.forEach((hid: string) => checks[hid] = true);

                    allLogs.push({
                        date: dateStr,
                        weekId,
                        checks
                    });
                }

                current.setDate(current.getDate() + 1);
            }
        });

        setLogs(allLogs);
        setWeeklyStats(stats);
    });

    // C. User Settings (and Profile)
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false,
                userName: data.userName || user.email || 'User',
                motto: data.motto || '',
                isAdmin: data.isAdmin || false,
                // Map New Fields
                alertTimes: data.alertTimes || null,
                isRanked: data.isRanked !== undefined ? data.isRanked : true, // Handle undefined as true
                isActive: data.isActive !== undefined ? data.isActive : true,
                deleteTime: data.deleteTime || null,
                dayStreak: data.dayStreak || 0,
                timeZone: data.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const dismissStreakNotification = () => {
      setStreakNotification(null);
  };

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      // Pass the count of currently active habits to update the week's lastPercent
      const activeCount = habits.filter(h => h.status === 'active').length;
      await toggleHabitCompletion(user.uid, habitId, date, activeCount);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      await restoreUserHabit(user.uid, id);
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      await commitOnboarding(user.uid, habitNames, user.email || 'User');
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const updateProfileAction = async (data: { userName?: string, motto?: string, alertTimes?: string[] | null, isRanked?: boolean }) => {
      if (!user) return;
      await updateUserProfile(user.uid, data);
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      weeklyStats,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      dataYear: new Date().getFullYear(),
      userName: userSettings?.userName || '',
      motto: userSettings?.motto || '',
      isAdmin: userSettings?.isAdmin || false,
      alertTimes: userSettings?.alertTimes || null,
      isRanked: userSettings?.isRanked !== undefined ? userSettings?.isRanked : true,
      isActive: userSettings?.isActive !== undefined ? userSettings?.isActive : true,
      deleteTime: userSettings?.deleteTime || null,
      dayStreak: userSettings?.dayStreak || 0,
      timeZone: userSettings?.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      streakNotification,
      dismissStreakNotification,
      addHabit, 
      toggleHabit, 
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      updateProfile: updateProfileAction,
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DEFAULT_SUGGESTIONS } from '../types';
import { Button } from '../components/Button';
import { X, ChevronLeft, Eye, EyeOff, CheckCircle2, Zap } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { auth } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';
import { checkUserHasHabits } from '../lib/firestore';

type Step = 'intro0' | 'intro1' | 'auth' | 'selection';

export const Onboarding: React.FC = () => {
  const { commitUserOnboarding } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<Step>('intro0');

  // Selection State
  const [selected, setSelected] = useState<string[]>([]);
  const [customHabit, setCustomHabit] = useState('');

  // Auth state
  const [isSignUp, setIsSignUp] = useState(false);
  const [isForgotPassword, setIsForgotPassword] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState('');
  const [resetMessage, setResetMessage] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const toggleSelection = (habit: string) => {
    if (selected.includes(habit)) {
      setSelected(prev => prev.filter(h => h !== habit));
    } else {
      setSelected(prev => [...prev, habit]);
    }
  };

  const addCustom = () => {
    if (!customHabit.trim()) return;
    setSelected(prev => [...prev, customHabit.trim()]);
    setCustomHabit('');
  };

  const finishSelection = async () => {
      if (selected.length === 0) return;
      setIsLoading(true);
      try {
          // Atomic commit of all selected habits and user status
          await commitUserOnboarding(selected);
          navigate('/today');
      } catch (error: any) {
          console.error(error);
          alert('Failed to complete onboarding: ' + error.message);
          setIsLoading(false);
      }
  };

  const handlePasswordReset = async () => {
    setAuthError('');
    setResetMessage('');
    if (!email) {
        setAuthError('Please enter your email address.');
        return;
    }

    setIsLoading(true);
    try {
        await sendPasswordResetEmail(auth, email);
        setResetMessage('Password reset email sent! Check your inbox.');
    } catch (error: any) {
        setAuthError(error.message);
    } finally {
        setIsLoading(false);
    }
  };

  const handleAuth = async () => {
    setAuthError('');
    if (!email || !password) {
        setAuthError('Please enter both email and password.');
        return;
    }

    setIsLoading(true);

    try {
        let cred;
        if (isSignUp) {
            cred = await createUserWithEmailAndPassword(auth, email, password);
            setIsLoading(false);
            setStep('selection');
        } else {
            cred = await signInWithEmailAndPassword(auth, email, password);
            // Check directly against Firestore using the UID from credentials
            // This avoids waiting for the AppContext listener to update
            const hasHabits = await checkUserHasHabits(cred.user.uid);

            if (hasHabits) {
                navigate('/today');
            } else {
                setIsLoading(false);
                setStep('selection');
            }
        }
    } catch (error: any) {
        setAuthError(error.message);
        setIsLoading(false);
    }
  };

  // --- VIEWS ---

  if (step === 'intro0') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in relative">
              <div className="flex-1 flex flex-col items-center justify-center">
                  <h1 className="text-3xl md:text-4xl font-bold text-ledger-text dark:text-ledger-textDark mb-10 tracking-tight leading-tight">
                      The log <br/>does not lie.
                  </h1>

                  <div className="space-y-6 max-w-xs mx-auto">
                    <p className="text-lg md:text-xl text-ledger-text dark:text-ledger-textDark font-medium leading-relaxed">
                        This is a place to record what you do.
                    </p>
                    <p className="text-lg md:text-xl text-ledger-muted font-medium leading-relaxed">
                        Not how you feel about it.
                    </p>
                  </div>
              </div>
              <div className="w-full">
                  <Button fullWidth onClick={() => setStep('intro1')}>Continue</Button>
              </div>
          </div>
      );
  }

  if (step === 'intro1') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in relative">
              <div className="flex-1 flex flex-col items-center justify-center">
                  <div className="w-16 h-16 bg-ledger-accent rounded-2xl flex items-center justify-center mb-6 shadow-lg text-white">
                      <CheckCircle2 size={32} />
                  </div>
                  <h1 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-4">
                      Accountability, <br/> Simplified.
                  </h1>
                  <p className="text-ledger-muted text-lg max-w-xs">
                      No bells, no whistles. Just a serious tool to track what matters daily.
                  </p>
              </div>
              <div className="w-full space-y-3">
                  <Button fullWidth onClick={() => setStep('auth')}>Get Started</Button>
                  <button onClick={() => setStep('intro0')} className="w-full py-2 text-xs font-bold uppercase text-ledger-muted hover:text-ledger-text transition-colors">Back</button>
              </div>
          </div>
      );
  }

  // Auth Step
  if (step === 'auth') {
    if (isForgotPassword) {
        return (
            <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
                <div className="mb-8 mt-2">
                    <button onClick={() => setIsForgotPassword(false)} className="flex items-center text-ledger-muted hover:text-ledger-text">
                        <ChevronLeft size={20} className="mr-1" /> Back
                    </button>
                </div>
                <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">Reset Password</h2>
                <div className="space-y-6 mt-6">
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent" />
                    {authError && <p className="text-red-500 text-sm">{authError}</p>}
                    {resetMessage && <p className="text-green-500 text-sm">{resetMessage}</p>}
                    <Button fullWidth onClick={handlePasswordReset} disabled={isLoading}>{isLoading ? 'Sending...' : 'Send Link'}</Button>
                </div>
            </div>
        );
    }

    return (
      <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
         <div className="mb-8 mt-2">
            <button onClick={() => setStep('intro1')} className="flex items-center text-ledger-muted hover:text-ledger-text">
                <ChevronLeft size={20} className="mr-1" /> Back
            </button>
         </div>

         <div className="flex-1 flex flex-col justify-center">
            <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">
              {isSignUp ? 'Create Account' : 'Welcome Back'}
            </h2>
            <p className="text-ledger-muted mb-8">Sync your data across devices.</p>

            <div className="space-y-6">
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted">Email</label>
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent" placeholder="you@example.com" />
                </div>
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted">Password</label>
                    <div className="relative">
                        <input type={showPassword ? "text" : "password"} value={password} onChange={e => setPassword(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent pr-10" placeholder="••••••" onKeyDown={e => e.key === 'Enter' && handleAuth()} />
                        <button onClick={() => setShowPassword(!showPassword)} className="absolute right-0 top-2 text-ledger-muted">
                            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                        </button>
                    </div>
                </div>

                {!isSignUp && (
                    <div className="flex justify-end">
                        <button onClick={() => setIsForgotPassword(true)} className="text-xs text-ledger-muted hover:text-ledger-accent">Forgot Password?</button>
                    </div>
                )}
            </div>

            {authError && <div className="mt-4 p-3 bg-red-50 dark:bg-red-900/20 text-red-600 rounded-lg text-sm">{authError}</div>}

            <div className="mt-8 space-y-4">
                <Button fullWidth onClick={handleAuth} disabled={isLoading}>
                    {isLoading ? 'Processing...' : (isSignUp ? 'Sign Up' : 'Log In')}
                </Button>
                <button onClick={() => { setIsSignUp(!isSignUp); setAuthError(''); }} className="w-full text-center text-xs text-ledger-muted hover:text-ledger-text">
                    {isSignUp ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
                </button>
            </div>
         </div>
      </div>
    );
  }

  // Selection Step
  if (step === 'selection') {
    return (
      <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col max-w-md mx-auto relative animate-fade-in">
        <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 mt-8">
              Habit Selection
            </h2>
            <p className="text-ledger-muted text-base mb-8">
              Select habits to start your journey.
            </p>

            {selected.length > 0 && (
                <div className="mb-6 space-y-2">
                    {selected.map((item) => (
                        <div key={item} className="flex items-center justify-between p-3 bg-white dark:bg-ledger-surfaceDark rounded-md border border-ledger-border dark:border-ledger-borderDark animate-fade-in">
                            <span className="font-medium text-ledger-text dark:text-ledger-textDark">{item}</span>
                            <button onClick={() => toggleSelection(item)} className="text-ledger-muted hover:text-red-500"><X size={16} /></button>
                        </div>
                    ))}
                </div>
            )}

            <div className="flex flex-wrap gap-2 mb-8">
                {DEFAULT_SUGGESTIONS.map(suggestion => (
                    <button
                        key={suggestion}
                        onClick={() => toggleSelection(suggestion)}
                        className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${selected.includes(suggestion) ? 'bg-ledger-accent text-white border-ledger-accent' : 'border-ledger-border dark:border-ledger-borderDark text-ledger-text dark:text-ledger-textDark'}`}
                    >
                        {suggestion}
                    </button>
                ))}
            </div>

            <div className="flex gap-2">
                <input 
                    type="text" 
                    value={customHabit}
                    onChange={(e) => setCustomHabit(e.target.value)}
                    placeholder="Custom habit..."
                    className="flex-1 bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent"
                    onKeyDown={(e) => e.key === 'Enter' && addCustom()}
                    maxLength={17}
                />
                <button onClick={addCustom} disabled={!customHabit} className="text-ledger-accent font-medium disabled:opacity-30">Add</button>
            </div>
        </div>
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark to-transparent pt-12">
            <Button fullWidth onClick={finishSelection} disabled={selected.length === 0 || isLoading}>
                {isLoading ? 'Creating Account...' : 'Complete Setup'}
            </Button>
        </div>
      </div>
    );
  }

  return null;
};

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { MAX_HABITS, Habit } from '../types';
import { Archive, ArrowUp, ArrowDown, RotateCcw, Plus, AlertCircle } from 'lucide-react';
import { Button } from '../components/Button';

// Sub-component for individual habit rows to manage focus/error states locally
const HabitItem: React.FC<{
  habit: Habit;
  index: number;
  isFirst: boolean;
  isLast: boolean;
  onUpdate: (id: string, name: string) => Promise<void>;
  onArchive: (id: string) => void;
  onMove: (index: number, direction: 'up' | 'down') => void;
}> = ({ habit, index, isFirst, isLast, onUpdate, onArchive, onMove }) => {
  const [name, setName] = useState(habit.name);
  const [error, setError] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  useEffect(() => {
      setName(habit.name);
  }, [habit.name]);

  const handleBlur = async () => {
      setIsFocused(false);
      const trimmed = name.trim();
      if (trimmed === habit.name) {
          setError('');
          return;
      }

      if (!trimmed) {
          setName(habit.name); // Revert if empty
          return;
      }

      try {
          setError('');
          await onUpdate(habit.id, trimmed);
      } catch (e: any) {
          // Revert visual to original if error (or keep dirty and show error)
          // Choosing to show error and keep dirty value so user can fix
          if (e.message.includes('already exists')) {
              setError('Name taken');
          } else {
              setError('Error');
          }
      }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
          e.currentTarget.blur();
      }
  };

  return (
    <div className={`bg-white dark:bg-ledger-surfaceDark p-4 rounded-xl shadow-sm border transition-all group relative ${error ? 'border-red-500' : 'border-ledger-border dark:border-ledger-borderDark hover:border-ledger-accent/50'}`}>
        <div className="flex items-center gap-3">
            <div className="flex flex-col gap-0.5 text-ledger-muted opacity-30 group-hover:opacity-100 transition-opacity">
                <button 
                    onClick={() => onMove(index, 'up')}
                    disabled={isFirst}
                    className="hover:text-ledger-accent disabled:opacity-20"
                >
                    <ArrowUp size={12} />
                </button>
                <button 
                    onClick={() => onMove(index, 'down')}
                    disabled={isLast}
                    className="hover:text-ledger-accent disabled:opacity-20"
                >
                    <ArrowDown size={12} />
                </button>
            </div>

            <div className="flex-1 relative">
                <input 
                    className={`w-full bg-transparent font-semibold text-lg focus:outline-none focus:text-ledger-accent placeholder-ledger-muted/50 ${error ? 'text-red-500' : 'text-ledger-text dark:text-ledger-textDark'}`}
                    value={name}
                    onChange={(e) => {
                        setName(e.target.value);
                        setError('');
                    }}
                    onFocus={() => setIsFocused(true)}
                    onBlur={handleBlur}
                    onKeyDown={handleKeyDown}
                    maxLength={17}
                />
            </div>

            <div className="flex items-center pl-4 border-l border-gray-100 dark:border-gray-800 ml-2">
                <button 
                    onClick={() => onArchive(habit.id)}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-lg text-ledger-muted hover:text-red-500 transition-colors"
                    title="Archive"
                >
                    <Archive size={18} />
                </button>
            </div>
        </div>

        {/* Footer Info: Error or Char Count */}
        {(isFocused || error) && (
            <div className="absolute bottom-1 right-4 flex items-center gap-2 pointer-events-none">
                {error && (
                    <span className="text-[10px] font-bold text-red-500 bg-red-50 dark:bg-red-900/20 px-1.5 rounded flex items-center gap-1">
                        <AlertCircle size={10} /> {error}
                    </span>
                )}
                {isFocused && (
                    <span className={`text-[10px] font-bold tracking-wider ${name.length >= 17 ? 'text-red-500' : 'text-ledger-muted/60'}`}>
                        {name.length}/17
                    </span>
                )}
            </div>
        )}
    </div>
  );
};

export const Habits: React.FC = () => {
  const { state, addHabit, updateHabitName, archiveHabit, restoreHabit, reorderHabits } = useApp();
  const [newHabitName, setNewHabitName] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [addError, setAddError] = useState('');

  const activeHabits = state.habits.filter(h => h.status === 'active');
  const archivedHabits = state.habits.filter(h => h.status === 'archived');
  const isLimitReached = activeHabits.length >= MAX_HABITS;

  const handleAdd = async () => {
    if (!newHabitName.trim()) return;
    try {
        setAddError('');
        await addHabit(newHabitName.trim());
        setNewHabitName('');
        setIsAdding(false);
    } catch (e: any) {
        if (e.message && e.message.includes('already exists')) {
            setAddError('Habit name taken (check archive)');
        } else {
            setAddError(e.message || 'Failed to create');
        }
    }
  };

  const handleUpdateNameWrapper = async (id: string, name: string) => {
     await updateHabitName(id, name);
  };

  const handleRestore = async (id: string) => {
      try {
          await restoreHabit(id);
      } catch (e: any) {
          if (e.message && e.message.includes('already exists')) {
              alert("A habit with this name already exists in your active list.");
          } else {
              alert(e.message);
          }
      }
  }

  const moveHabit = (index: number, direction: 'up' | 'down') => {
    const newIndex = direction === 'up' ? index - 1 : index + 1;
    if (newIndex >= 0 && newIndex < activeHabits.length) {
        reorderHabits(index, newIndex);
    }
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-6 overflow-y-auto no-scrollbar">
      <header className="mb-8 flex justify-between items-center">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">Habits</h1>
        <div className="text-[10px] font-bold text-ledger-muted uppercase bg-gray-200 dark:bg-white/10 px-2.5 py-1 rounded-full tracking-wider">
            {activeHabits.length} / {MAX_HABITS}
        </div>
      </header>

      {/* Active List */}
      <div className="space-y-3 mb-8">
        {activeHabits.map((habit, index) => (
            <HabitItem 
                key={habit.id}
                habit={habit}
                index={index}
                isFirst={index === 0}
                isLast={index === activeHabits.length - 1}
                onUpdate={handleUpdateNameWrapper}
                onArchive={archiveHabit}
                onMove={moveHabit}
            />
        ))}

        {isAdding ? (
            <div className={`p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border-2 ${addError ? 'border-red-500' : 'border-ledger-accent'} animate-fade-in shadow-md`}>
                <div className="flex items-center gap-3 mb-1">
                    <input 
                        autoFocus
                        value={newHabitName}
                        onChange={e => {
                            setNewHabitName(e.target.value);
                            if (addError) setAddError('');
                        }}
                        placeholder="New habit name..."
                        className="flex-1 bg-transparent focus:outline-none text-lg font-semibold text-ledger-text dark:text-ledger-textDark placeholder-ledger-muted/50"
                        onKeyDown={e => e.key === 'Enter' && handleAdd()}
                        maxLength={17}
                    />
                    <button onClick={handleAdd} className="text-sm font-bold bg-ledger-accent text-white px-3 py-1.5 rounded-md hover:opacity-90">Save</button>
                </div>
                <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold text-red-500 h-4 flex items-center">
                        {addError && <><AlertCircle size={10} className="mr-1"/> {addError}</>}
                    </span>
                    <span className={`text-[10px] font-bold tracking-wider ${newHabitName.length >= 17 ? 'text-red-500' : 'text-ledger-muted'}`}>
                        {newHabitName.length}/17
                    </span>
                </div>
            </div>
        ) : (
             <Button 
                variant="secondary" 
                fullWidth 
                onClick={() => setIsAdding(true)}
                disabled={isLimitReached}
                className="border-dashed h-14"
            >
                <Plus size={20} className="mr-2 opacity-60" />
                {isLimitReached ? 'Limit reached' : 'Create new habit'}
            </Button>
        )}
      </div>

      {/* Archived Section */}
      {archivedHabits.length > 0 && (
        <div className="mt-auto pt-8 pb-4">
            <h3 className="text-[10px] font-bold uppercase text-ledger-muted tracking-widest mb-4 ml-1">Archived</h3>
            <div className="space-y-2 opacity-80 hover:opacity-100 transition-opacity">
                {archivedHabits.map(habit => (
                    <div key={habit.id} className="flex items-center justify-between p-3 rounded-lg border border-transparent hover:bg-white dark:hover:bg-white/5 transition-colors group">
                        <span className="text-ledger-muted line-through decoration-2 decoration-ledger-muted/30 font-medium">{habit.name}</span>
                        <button 
                            onClick={() => handleRestore(habit.id)}
                            disabled={isLimitReached}
                            className="text-xs font-bold text-ledger-accent hover:bg-ledger-accent/10 px-3 py-1.5 rounded transition-colors disabled:opacity-30 disabled:cursor-not-allowed flex items-center gap-1.5"
                        >
                            <RotateCcw size={12} />
                            RESTORE
                        </button>
                    </div>
                ))}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    restoreUserHabit,
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    commitOnboarding,
    getWeekParams,
    getWeekRange,
    updateUserProfile,
    toLocalISOString,
    updateAppStreak
} from '../lib/firestore';

interface UserSettings {
    theme: ThemeOption;
    isOnboarded: boolean;
    userName: string;
    motto: string;
    isAdmin: boolean;
    // New Fields
    alertTimes: string[] | null;
    isRanked: boolean;
    isActive: boolean;
    deleteTime: string | null;
    dayStreak: number;
    timeZone: string;
}

interface AppContextType {
  state: AppState;
  streakNotification: { visible: boolean, days: number } | null;
  dismissStreakNotification: () => void;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  updateProfile: (data: { 
      userName?: string; 
      motto?: string; 
      alertTimes?: string[] | null;
      isRanked?: boolean;
      isActive?: boolean;
      deleteTime?: string | null; 
  }) => Promise<void>;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  weeklyStats: {},
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  dataYear: new Date().getFullYear(),
  userName: '',
  motto: '',
  isAdmin: false,
  alertTimes: null,
  isRanked: true, // Default to true
  isActive: true,
  deleteTime: null,
  dayStreak: 0,
  timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [streakNotification, setStreakNotification] = useState<{ visible: boolean, days: number } | null>(null);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [weeklyStats, setWeeklyStats] = useState<Record<string, number>>({});
  const [userSettings, setUserSettings] = useState<UserSettings | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setWeeklyStats({});
        setUserSettings(null);
        setIsLoading(false);
        setStreakNotification(null);
      } else {
         // Check streak on login/load
         // We do this once here, not inside onSnapshot to avoid loops
         updateAppStreak(u.uid).then((res) => {
             if (res && res.showedAnimation) {
                 setStreakNotification({ visible: true, days: res.streak });
             }
         });
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const today = new Date();
    // CRITICAL: Use the year from getWeekParams to ensure we listen to the correct collection
    const { year: currentWeekYear } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs & Weekly Stats (Listen to the Calculated Year Collection)
    const yearCollection = collection(db, `users/${userId}/${currentWeekYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];
        let stats: Record<string, number> = {};

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // 1. Capture Weekly Percent
            if (typeof data.lastPercent === 'number') {
                stats[weekId] = data.lastPercent;
            }

            // 2. Reconstruct Logs from strict Week Ranges
            const weekNum = parseInt(weekId.replace('week', ''));
            const { start, end } = getWeekRange(parseInt(currentWeekYear), weekNum);

            // Iterate from start to end of that week
            const current = new Date(start);
            while (current <= end) {
                const dayName = current.toLocaleDateString('en-US', { weekday: 'short' }).toLowerCase();
                const habitIds = data[dayName];

                if (Array.isArray(habitIds) && habitIds.length > 0) {
                    const dateStr = toLocalISOString(current);
                    const checks: Record<string, boolean> = {};
                    habitIds.forEach((hid: string) => checks[hid] = true);

                    allLogs.push({
                        date: dateStr,
                        weekId,
                        checks
                    });
                }

                current.setDate(current.getDate() + 1);
            }
        });

        setLogs(allLogs);
        setWeeklyStats(stats);
    });

    // C. User Settings (and Profile)
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false,
                userName: data.userName || user.email || 'User',
                motto: data.motto || '',
                isAdmin: data.isAdmin || false,
                // Map New Fields
                alertTimes: data.alertTimes || null,
                isRanked: data.isRanked !== undefined ? data.isRanked : true, // Handle undefined as true
                isActive: data.isActive !== undefined ? data.isActive : true,
                deleteTime: data.deleteTime || null,
                dayStreak: data.dayStreak || 0,
                timeZone: data.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const dismissStreakNotification = () => {
      setStreakNotification(null);
  };

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      // Pass the count of currently active habits to update the week's lastPercent
      const activeCount = habits.filter(h => h.status === 'active').length;
      await toggleHabitCompletion(user.uid, habitId, date, activeCount);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      await restoreUserHabit(user.uid, id);
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      await commitOnboarding(user.uid, habitNames, user.email || 'User');
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const updateProfileAction = async (data: { 
      userName?: string; 
      motto?: string; 
      alertTimes?: string[] | null;
      isRanked?: boolean;
      isActive?: boolean;
      deleteTime?: string | null;
  }) => {
      if (!user) return;
      await updateUserProfile(user.uid, data);
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      weeklyStats,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      dataYear: new Date().getFullYear(),
      userName: userSettings?.userName || '',
      motto: userSettings?.motto || '',
      isAdmin: userSettings?.isAdmin || false,
      alertTimes: userSettings?.alertTimes || null,
      isRanked: userSettings?.isRanked !== undefined ? userSettings?.isRanked : true,
      isActive: userSettings?.isActive !== undefined ? userSettings?.isActive : true,
      deleteTime: userSettings?.deleteTime || null,
      dayStreak: userSettings?.dayStreak || 0,
      timeZone: userSettings?.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      streakNotification,
      dismissStreakNotification,
      addHabit, 
      toggleHabit, 
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      updateProfile: updateProfileAction,
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DEFAULT_SUGGESTIONS } from '../types';
import { Button } from '../components/Button';
import { X, ChevronLeft, Eye, EyeOff, CheckCircle2, TrendingUp } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { auth } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';
import { checkUserHasHabits } from '../lib/firestore';

type Step = 'intro0' | 'intro1' | 'auth' | 'selection';

export const Onboarding: React.FC = () => {
  const { commitUserOnboarding } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<Step>('intro0');

  // Selection State
  const [selected, setSelected] = useState<string[]>([]);
  const [customHabit, setCustomHabit] = useState('');

  // Auth state
  const [isSignUp, setIsSignUp] = useState(false);
  const [isForgotPassword, setIsForgotPassword] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState('');
  const [resetMessage, setResetMessage] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const toggleSelection = (habit: string) => {
    if (selected.includes(habit)) {
      setSelected(prev => prev.filter(h => h !== habit));
    } else {
      setSelected(prev => [...prev, habit]);
    }
  };

  const addCustom = () => {
    if (!customHabit.trim()) return;
    setSelected(prev => [...prev, customHabit.trim()]);
    setCustomHabit('');
  };

  const finishSelection = async () => {
      if (selected.length === 0) return;
      setIsLoading(true);
      try {
          // Atomic commit of all selected habits and user status
          await commitUserOnboarding(selected);
          navigate('/today');
      } catch (error: any) {
          console.error(error);
          alert('Failed to complete onboarding: ' + error.message);
          setIsLoading(false);
      }
  };

  const handlePasswordReset = async () => {
    setAuthError('');
    setResetMessage('');
    if (!email) {
        setAuthError('Please enter your email address.');
        return;
    }

    setIsLoading(true);
    try {
        await sendPasswordResetEmail(auth, email);
        setResetMessage('Password reset email sent! Check your inbox.');
    } catch (error: any) {
        setAuthError(error.message);
    } finally {
        setIsLoading(false);
    }
  };

  const handleAuth = async () => {
    setAuthError('');
    if (!email || !password) {
        setAuthError('Please enter both email and password.');
        return;
    }

    setIsLoading(true);

    try {
        let cred;
        if (isSignUp) {
            cred = await createUserWithEmailAndPassword(auth, email, password);
            setIsLoading(false);
            setStep('selection');
        } else {
            cred = await signInWithEmailAndPassword(auth, email, password);
            // Check directly against Firestore using the UID from credentials
            // This avoids waiting for the AppContext listener to update
            const hasHabits = await checkUserHasHabits(cred.user.uid);

            if (hasHabits) {
                navigate('/today');
            } else {
                setIsLoading(false);
                setStep('selection');
            }
        }
    } catch (error: any) {
        setAuthError(error.message);
        setIsLoading(false);
    }
  };

  // --- VIEWS ---

  if (step === 'intro0') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col relative overflow-hidden">
              {/* Background Decoration */}
              <div className="absolute inset-0 z-0 opacity-[0.07] pointer-events-none" 
                   style={{ 
                       backgroundImage: 'radial-gradient(circle, currentColor 1px, transparent 1px)', 
                       backgroundSize: '24px 24px' 
                   }} 
              />

              <div className="flex-1 flex flex-col justify-center px-8 z-10 animate-fade-in">
                  <div className="mb-12">
                     <TrendingUp className="text-ledger-accent mb-6" size={32} />
                  </div>

                  <h1 className="text-5xl md:text-6xl font-extrabold text-ledger-text dark:text-ledger-textDark tracking-tighter leading-[1.1] mb-2">
                      The log
                  </h1>
                  <h1 className="text-5xl md:text-6xl font-serif italic text-ledger-text dark:text-ledger-textDark tracking-tight leading-[1.1] mb-8">
                      does not lie.
                  </h1>

                  <div className="w-12 h-1 bg-ledger-accent mb-8 rounded-full" />

                  <div className="space-y-2">
                    <p className="text-lg text-ledger-text dark:text-ledger-textDark font-medium">
                        This is a place to record what you do.
                    </p>
                    <p className="text-lg text-ledger-muted font-normal">
                        Not how you feel about it.
                    </p>
                  </div>
              </div>

              <div className="p-8 z-10 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark to-transparent">
                  <Button fullWidth onClick={() => setStep('intro1')}>Continue</Button>
              </div>
          </div>
      );
  }

  if (step === 'intro1') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in relative">
              <div className="flex-1 flex flex-col items-center justify-center">
                  <div className="w-20 h-20 bg-ledger-accent/10 rounded-3xl flex items-center justify-center mb-8 shadow-sm">
                      <CheckCircle2 size={40} className="text-ledger-accent" />
                  </div>
                  <h1 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-4 tracking-tight">
                      Accountability,<br/>Simplified.
                  </h1>
                  <p className="text-ledger-muted text-lg max-w-xs leading-relaxed">
                      No bells, no whistles.<br/>Just a serious tool to track what matters daily.
                  </p>
              </div>
              <div className="w-full space-y-4">
                  <Button fullWidth onClick={() => setStep('auth')}>Get Started</Button>
                  <button onClick={() => setStep('intro0')} className="w-full py-2 text-xs font-bold uppercase text-ledger-muted hover:text-ledger-text transition-colors tracking-widest">Back</button>
              </div>
          </div>
      );
  }

  // Auth Step
  if (step === 'auth') {
    if (isForgotPassword) {
        return (
            <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
                <div className="mb-8 mt-2">
                    <button onClick={() => setIsForgotPassword(false)} className="flex items-center text-ledger-muted hover:text-ledger-text">
                        <ChevronLeft size={20} className="mr-1" /> Back
                    </button>
                </div>
                <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">Reset Password</h2>
                <div className="space-y-6 mt-6">
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent" />
                    {authError && <p className="text-red-500 text-sm">{authError}</p>}
                    {resetMessage && <p className="text-green-500 text-sm">{resetMessage}</p>}
                    <Button fullWidth onClick={handlePasswordReset} disabled={isLoading}>{isLoading ? 'Sending...' : 'Send Link'}</Button>
                </div>
            </div>
        );
    }

    return (
      <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
         <div className="mb-8 mt-2">
            <button onClick={() => setStep('intro1')} className="flex items-center text-ledger-muted hover:text-ledger-text">
                <ChevronLeft size={20} className="mr-1" /> Back
            </button>
         </div>

         <div className="flex-1 flex flex-col justify-center">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 tracking-tight">
              {isSignUp ? 'Create Account' : 'Welcome Back'}
            </h2>
            <p className="text-ledger-muted mb-10">Sync your data across devices.</p>

            <div className="space-y-8">
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted mb-2 block tracking-wider">Email</label>
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-lg text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent placeholder-ledger-muted/30" placeholder="you@example.com" />
                </div>
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted mb-2 block tracking-wider">Password</label>
                    <div className="relative">
                        <input type={showPassword ? "text" : "password"} value={password} onChange={e => setPassword(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-lg text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent pr-10 placeholder-ledger-muted/30" placeholder="••••••" onKeyDown={e => e.key === 'Enter' && handleAuth()} />
                        <button onClick={() => setShowPassword(!showPassword)} className="absolute right-0 top-2 text-ledger-muted hover:text-ledger-text transition-colors">
                            {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                        </button>
                    </div>
                </div>

                {!isSignUp && (
                    <div className="flex justify-end">
                        <button onClick={() => setIsForgotPassword(true)} className="text-xs font-medium text-ledger-muted hover:text-ledger-accent transition-colors">Forgot Password?</button>
                    </div>
                )}
            </div>

            {authError && <div className="mt-6 p-3 bg-red-50 dark:bg-red-900/20 text-red-600 rounded-lg text-sm font-medium">{authError}</div>}

            <div className="mt-10 space-y-4">
                <Button fullWidth onClick={handleAuth} disabled={isLoading}>
                    {isLoading ? 'Processing...' : (isSignUp ? 'Sign Up' : 'Log In')}
                </Button>
                <button onClick={() => { setIsSignUp(!isSignUp); setAuthError(''); }} className="w-full text-center text-xs font-bold uppercase text-ledger-muted hover:text-ledger-text transition-colors tracking-widest">
                    {isSignUp ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
                </button>
            </div>
         </div>
      </div>
    );
  }

  // Selection Step
  if (step === 'selection') {
    return (
      <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col max-w-md mx-auto relative animate-fade-in">
        <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 mt-8 tracking-tight">
              Habit Selection
            </h2>
            <p className="text-ledger-muted text-base mb-8">
              Select habits to start your journey.
            </p>

            {selected.length > 0 && (
                <div className="mb-6 space-y-2">
                    {selected.map((item) => (
                        <div key={item} className="flex items-center justify-between p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark animate-fade-in shadow-sm">
                            <span className="font-semibold text-ledger-text dark:text-ledger-textDark">{item}</span>
                            <button onClick={() => toggleSelection(item)} className="text-ledger-muted hover:text-red-500 transition-colors"><X size={18} /></button>
                        </div>
                    ))}
                </div>
            )}

            <div className="flex flex-wrap gap-2.5 mb-8">
                {DEFAULT_SUGGESTIONS.map(suggestion => (
                    <button
                        key={suggestion}
                        onClick={() => toggleSelection(suggestion)}
                        className={`px-5 py-2.5 rounded-full text-sm font-semibold border transition-all ${selected.includes(suggestion) ? 'bg-ledger-accent text-white border-ledger-accent shadow-md' : 'border-ledger-border dark:border-ledger-borderDark text-ledger-text dark:text-ledger-textDark hover:bg-gray-50 dark:hover:bg-white/5'}`}
                    >
                        {suggestion}
                    </button>
                ))}
            </div>

            <div className="flex gap-3 items-end">
                <div className="flex-1">
                     <label className="text-[10px] font-bold uppercase text-ledger-muted mb-1 block">Custom Habit</label>
                     <input 
                        type="text" 
                        value={customHabit}
                        onChange={(e) => setCustomHabit(e.target.value)}
                        placeholder="e.g. Drink Water"
                        className="w-full bg-transparent border-b-2 border-ledger-border dark:border-ledger-borderDark py-2 text-lg font-medium text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent placeholder-ledger-muted/30"
                        onKeyDown={(e) => e.key === 'Enter' && addCustom()}
                        maxLength={17}
                    />
                </div>
                <button onClick={addCustom} disabled={!customHabit} className="mb-2 text-sm font-bold bg-ledger-accent text-white px-4 py-2 rounded-lg hover:opacity-90 disabled:opacity-30 disabled:cursor-not-allowed transition-all">Add</button>
            </div>
        </div>
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark via-ledger-bg dark:via-ledger-bgDark to-transparent pt-12">
            <Button fullWidth onClick={finishSelection} disabled={selected.length === 0 || isLoading}>
                {isLoading ? 'Creating Account...' : 'Complete Setup'}
            </Button>
        </div>
      </div>
    );
  }

  return null;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DEFAULT_SUGGESTIONS } from '../types';
import { Button } from '../components/Button';
import { X, ChevronLeft, Eye, EyeOff, CheckCircle2, TrendingUp } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { auth } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';
import { checkUserHasHabits } from '../lib/firestore';

type Step = 'intro0' | 'intro1' | 'auth' | 'selection';

export const Onboarding: React.FC = () => {
  const { commitUserOnboarding } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<Step>('intro0');

  // Selection State
  const [selected, setSelected] = useState<string[]>([]);
  const [customHabit, setCustomHabit] = useState('');

  // Auth state
  const [isSignUp, setIsSignUp] = useState(false);
  const [isForgotPassword, setIsForgotPassword] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState('');
  const [resetMessage, setResetMessage] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const toggleSelection = (habit: string) => {
    if (selected.includes(habit)) {
      setSelected(prev => prev.filter(h => h !== habit));
    } else {
      setSelected(prev => [...prev, habit]);
    }
  };

  const addCustom = () => {
    if (!customHabit.trim()) return;
    setSelected(prev => [...prev, customHabit.trim()]);
    setCustomHabit('');
  };

  const finishSelection = async () => {
      if (selected.length === 0) return;
      setIsLoading(true);
      try {
          // Atomic commit of all selected habits and user status
          await commitUserOnboarding(selected);
          navigate('/today');
      } catch (error: any) {
          console.error(error);
          alert('Failed to complete onboarding: ' + error.message);
          setIsLoading(false);
      }
  };

  const handlePasswordReset = async () => {
    setAuthError('');
    setResetMessage('');
    if (!email) {
        setAuthError('Please enter your email address.');
        return;
    }

    setIsLoading(true);
    try {
        await sendPasswordResetEmail(auth, email);
        setResetMessage('Password reset email sent! Check your inbox.');
    } catch (error: any) {
        setAuthError(error.message);
    } finally {
        setIsLoading(false);
    }
  };

  const handleAuth = async () => {
    setAuthError('');
    if (!email || !password) {
        setAuthError('Please enter both email and password.');
        return;
    }

    setIsLoading(true);

    try {
        let cred;
        if (isSignUp) {
            cred = await createUserWithEmailAndPassword(auth, email, password);
            setIsLoading(false);
            setStep('selection');
        } else {
            cred = await signInWithEmailAndPassword(auth, email, password);
            // Check directly against Firestore using the UID from credentials
            // This avoids waiting for the AppContext listener to update
            const hasHabits = await checkUserHasHabits(cred.user.uid);

            if (hasHabits) {
                navigate('/today');
            } else {
                setIsLoading(false);
                setStep('selection');
            }
        }
    } catch (error: any) {
        setAuthError(error.message);
        setIsLoading(false);
    }
  };

  // --- VIEWS ---

  if (step === 'intro0') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col relative overflow-hidden">
              {/* Background Pattern */}
              <div className="absolute inset-0 opacity-[0.05] pointer-events-none" 
                   style={{ 
                       backgroundImage: 'radial-gradient(circle, currentColor 1px, transparent 1px)', 
                       backgroundSize: '32px 32px' 
                   }} 
              />

              <div className="flex-1 flex flex-col justify-center px-8 z-10 animate-fade-in pb-12">
                  <div className="w-14 h-14 bg-ledger-accent rounded-xl flex items-center justify-center mb-10 shadow-xl shadow-ledger-accent/20">
                     <TrendingUp className="text-white" size={28} strokeWidth={2.5} />
                  </div>

                  <h1 className="text-6xl md:text-7xl font-black text-ledger-text dark:text-ledger-textDark tracking-tighter leading-[0.9] mb-3">
                      THE<br/>LOG
                  </h1>
                  <h1 className="text-4xl md:text-5xl font-mono text-ledger-muted tracking-tighter leading-none mb-10">
                      DOES NOT<br/>LIE.
                  </h1>

                  <div className="w-20 h-1.5 bg-ledger-accent mb-10" />

                  <div className="space-y-4">
                    <p className="text-2xl text-ledger-text dark:text-ledger-textDark font-bold tracking-tight">
                        Record what you do.
                    </p>
                    <p className="text-lg text-ledger-muted font-normal max-w-xs">
                        Not how you feel about it.
                    </p>
                  </div>
              </div>

              <div className="p-8 z-10 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark to-transparent">
                  <Button fullWidth onClick={() => setStep('intro1')}>Continue</Button>
              </div>
          </div>
      );
  }

  if (step === 'intro1') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in relative">
              <div className="flex-1 flex flex-col items-center justify-center">
                  <div className="w-20 h-20 bg-ledger-surface dark:bg-ledger-surfaceDark border border-ledger-border dark:border-ledger-borderDark rounded-2xl flex items-center justify-center mb-8 shadow-sm rotate-3">
                      <CheckCircle2 size={40} className="text-ledger-accent" />
                  </div>
                  <h1 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-4 tracking-tight">
                      Accountability,<br/>Simplified.
                  </h1>
                  <p className="text-ledger-muted text-lg max-w-xs leading-relaxed">
                      No bells, no whistles.<br/>Just a serious tool to track what matters daily.
                  </p>
              </div>
              <div className="w-full space-y-4">
                  <Button fullWidth onClick={() => setStep('auth')}>Get Started</Button>
                  <button onClick={() => setStep('intro0')} className="w-full py-2 text-xs font-bold uppercase text-ledger-muted hover:text-ledger-text transition-colors tracking-widest">Back</button>
              </div>
          </div>
      );
  }

  // Auth Step
  if (step === 'auth') {
    if (isForgotPassword) {
        return (
            <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
                <div className="mb-8 mt-2">
                    <button onClick={() => setIsForgotPassword(false)} className="flex items-center text-ledger-muted hover:text-ledger-text">
                        <ChevronLeft size={20} className="mr-1" /> Back
                    </button>
                </div>
                <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">Reset Password</h2>
                <div className="space-y-6 mt-6">
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent" />
                    {authError && <p className="text-red-500 text-sm">{authError}</p>}
                    {resetMessage && <p className="text-green-500 text-sm">{resetMessage}</p>}
                    <Button fullWidth onClick={handlePasswordReset} disabled={isLoading}>{isLoading ? 'Sending...' : 'Send Link'}</Button>
                </div>
            </div>
        );
    }

    return (
      <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
         <div className="mb-8 mt-2">
            <button onClick={() => setStep('intro1')} className="flex items-center text-ledger-muted hover:text-ledger-text">
                <ChevronLeft size={20} className="mr-1" /> Back
            </button>
         </div>

         <div className="flex-1 flex flex-col justify-center">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 tracking-tight">
              {isSignUp ? 'Create Account' : 'Welcome Back'}
            </h2>
            <p className="text-ledger-muted mb-10">Sync your data across devices.</p>

            <div className="space-y-8">
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted mb-2 block tracking-wider">Email</label>
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-lg text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent placeholder-ledger-muted/30" placeholder="you@example.com" />
                </div>
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted mb-2 block tracking-wider">Password</label>
                    <div className="relative">
                        <input type={showPassword ? "text" : "password"} value={password} onChange={e => setPassword(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-lg text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent pr-10 placeholder-ledger-muted/30" placeholder="••••••" onKeyDown={e => e.key === 'Enter' && handleAuth()} />
                        <button onClick={() => setShowPassword(!showPassword)} className="absolute right-0 top-2 text-ledger-muted hover:text-ledger-text transition-colors">
                            {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                        </button>
                    </div>
                </div>

                {!isSignUp && (
                    <div className="flex justify-end">
                        <button onClick={() => setIsForgotPassword(true)} className="text-xs font-medium text-ledger-muted hover:text-ledger-accent transition-colors">Forgot Password?</button>
                    </div>
                )}
            </div>

            {authError && <div className="mt-6 p-3 bg-red-50 dark:bg-red-900/20 text-red-600 rounded-lg text-sm font-medium">{authError}</div>}

            <div className="mt-10 space-y-4">
                <Button fullWidth onClick={handleAuth} disabled={isLoading}>
                    {isLoading ? 'Processing...' : (isSignUp ? 'Sign Up' : 'Log In')}
                </Button>
                <button onClick={() => { setIsSignUp(!isSignUp); setAuthError(''); }} className="w-full text-center text-xs font-bold uppercase text-ledger-muted hover:text-ledger-text transition-colors tracking-widest">
                    {isSignUp ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
                </button>
            </div>
         </div>
      </div>
    );
  }

  // Selection Step
  if (step === 'selection') {
    return (
      <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col max-w-md mx-auto relative animate-fade-in">
        <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 mt-8 tracking-tight">
              Habit Selection
            </h2>
            <p className="text-ledger-muted text-base mb-8">
              Select habits to start your journey.
            </p>

            {selected.length > 0 && (
                <div className="mb-6 space-y-2">
                    {selected.map((item) => (
                        <div key={item} className="flex items-center justify-between p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark animate-fade-in shadow-sm">
                            <span className="font-semibold text-ledger-text dark:text-ledger-textDark">{item}</span>
                            <button onClick={() => toggleSelection(item)} className="text-ledger-muted hover:text-red-500 transition-colors"><X size={18} /></button>
                        </div>
                    ))}
                </div>
            )}

            <div className="flex flex-wrap gap-2.5 mb-8">
                {DEFAULT_SUGGESTIONS.map(suggestion => (
                    <button
                        key={suggestion}
                        onClick={() => toggleSelection(suggestion)}
                        className={`px-5 py-2.5 rounded-full text-sm font-semibold border transition-all ${selected.includes(suggestion) ? 'bg-ledger-accent text-white border-ledger-accent shadow-md' : 'border-ledger-border dark:border-ledger-borderDark text-ledger-text dark:text-ledger-textDark hover:bg-gray-50 dark:hover:bg-white/5'}`}
                    >
                        {suggestion}
                    </button>
                ))}
            </div>

            <div className="flex gap-3 items-end">
                <div className="flex-1">
                     <label className="text-[10px] font-bold uppercase text-ledger-muted mb-1 block">Custom Habit</label>
                     <input 
                        type="text" 
                        value={customHabit}
                        onChange={(e) => setCustomHabit(e.target.value)}
                        placeholder="e.g. Drink Water"
                        className="w-full bg-transparent border-b-2 border-ledger-border dark:border-ledger-borderDark py-2 text-lg font-medium text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent placeholder-ledger-muted/30"
                        onKeyDown={(e) => e.key === 'Enter' && addCustom()}
                        maxLength={17}
                    />
                </div>
                <button onClick={addCustom} disabled={!customHabit} className="mb-2 text-sm font-bold bg-ledger-accent text-white px-4 py-2 rounded-lg hover:opacity-90 disabled:opacity-30 disabled:cursor-not-allowed transition-all">Add</button>
            </div>
        </div>
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark via-ledger-bg dark:via-ledger-bgDark to-transparent pt-12">
            <Button fullWidth onClick={finishSelection} disabled={selected.length === 0 || isLoading}>
                {isLoading ? 'Creating Account...' : 'Complete Setup'}
            </Button>
        </div>
      </div>
    );
  }

  return null;
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    setDoc
} from 'firebase/firestore';
import { 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    restoreUserHabit,
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    commitOnboarding,
    getWeekParams,
    getWeekRange,
    updateUserProfile,
    toLocalISOString,
    updateAppStreak
} from '../lib/firestore';

interface UserSettings {
    theme: ThemeOption;
    isOnboarded: boolean;
    userName: string;
    motto: string;
    isAdmin: boolean;
    // New Fields
    alertTimes: string[] | null;
    isRanked: boolean;
    isActive: boolean;
    deleteTime: string | null;
    dayStreak: number;
    timeZone: string;
}

interface AppContextType {
  state: AppState;
  streakNotification: { visible: boolean, days: number } | null;
  dismissStreakNotification: () => void;
  addHabit: (name: string) => Promise<void>;
  toggleHabit: (habitId: string, date: string) => void;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => Promise<void>;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  commitUserOnboarding: (habitNames: string[]) => Promise<void>;
  setTheme: (theme: ThemeOption) => void;
  updateProfile: (data: { 
      userName?: string; 
      motto?: string; 
      alertTimes?: string[] | null;
      isRanked?: boolean;
      isActive?: boolean;
      deleteTime?: string | null; 
  }) => Promise<void>;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  weeklyStats: {},
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  dataYear: new Date().getFullYear(),
  userName: '',
  motto: '',
  isAdmin: false,
  alertTimes: null,
  isRanked: true, // Default to true
  isActive: true,
  deleteTime: null,
  dayStreak: 0,
  timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [streakNotification, setStreakNotification] = useState<{ visible: boolean, days: number } | null>(null);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [weeklyStats, setWeeklyStats] = useState<Record<string, number>>({});
  const [userSettings, setUserSettings] = useState<UserSettings | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setWeeklyStats({});
        setUserSettings(null);
        setIsLoading(false);
        setStreakNotification(null);
      } else {
         // Check streak on login/load
         // We do this once here, not inside onSnapshot to avoid loops
         updateAppStreak(u.uid).then((res) => {
             if (res && res.showedAnimation) {
                 setStreakNotification({ visible: true, days: res.streak });
             }
         });
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const today = new Date();
    // CRITICAL: Use the year from getWeekParams to ensure we listen to the correct collection
    const { year: currentWeekYear } = getWeekParams(today);

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs & Weekly Stats (Listen to the Calculated Year Collection)
    const yearCollection = collection(db, `users/${userId}/${currentWeekYear}`);
    const unsubYear = onSnapshot(yearCollection, (snapshot) => {
        let allLogs: DailyLog[] = [];
        let stats: Record<string, number> = {};

        snapshot.docs.forEach(doc => {
            const weekId = doc.id;
            const data = doc.data();

            // 1. Capture Weekly Percent
            if (typeof data.lastPercent === 'number') {
                stats[weekId] = data.lastPercent;
            }

            // 2. Reconstruct Logs from strict Week Ranges
            const weekNum = parseInt(weekId.replace('week', ''));
            const { start, end } = getWeekRange(parseInt(currentWeekYear), weekNum);

            // Iterate from start to end of that week
            const current = new Date(start);
            while (current <= end) {
                const dayName = current.toLocaleDateString('en-US', { weekday: 'short' }).toLowerCase();
                const habitIds = data[dayName];

                if (Array.isArray(habitIds) && habitIds.length > 0) {
                    const dateStr = toLocalISOString(current);
                    const checks: Record<string, boolean> = {};
                    habitIds.forEach((hid: string) => checks[hid] = true);

                    allLogs.push({
                        date: dateStr,
                        weekId,
                        checks
                    });
                }

                current.setDate(current.getDate() + 1);
            }
        });

        setLogs(allLogs);
        setWeeklyStats(stats);
    });

    // C. User Settings (and Profile)
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false,
                userName: data.userName || user.email || 'User',
                motto: data.motto || '',
                isAdmin: data.isAdmin || false,
                // Map New Fields
                alertTimes: data.alertTimes || null,
                isRanked: data.isRanked !== undefined ? data.isRanked : true, // Handle undefined as true
                isActive: data.isActive !== undefined ? data.isActive : true,
                deleteTime: data.deleteTime || null,
                dayStreak: data.dayStreak || 0,
                timeZone: data.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
            });
            setIsLoading(false);
        } else {
            setIsLoading(false);
        }
    });

    return () => {
      unsubHabits();
      unsubYear();
      unsubUser();
    };
  }, [user]);

  // --- ACTIONS ---

  const dismissStreakNotification = () => {
      setStreakNotification(null);
  };

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      // Pass the count of currently active habits to update the week's lastPercent
      const activeCount = habits.filter(h => h.status === 'active').length;
      await toggleHabitCompletion(user.uid, habitId, date, activeCount);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      await restoreUserHabit(user.uid, id);
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const commitUserOnboarding = async (habitNames: string[]) => {
      if (!user) return;
      await commitOnboarding(user.uid, habitNames, user.email || 'User');
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const updateProfileAction = async (data: { 
      userName?: string; 
      motto?: string; 
      alertTimes?: string[] | null;
      isRanked?: boolean;
      isActive?: boolean;
      deleteTime?: string | null;
  }) => {
      if (!user) return;
      await updateUserProfile(user.uid, data);
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    // Clear all potential themes
    html.classList.remove(
      'dark', 'theme-light', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );

    const theme = userSettings?.theme || 'dark';

    // Logic: Dark is default in root. 
    // If 'light', add theme-light and REMOVE dark class.
    // If 'dark' (or others which are dark-based), add theme class AND 'dark' class.

    if (theme === 'light') {
        html.classList.add('theme-light');
        html.classList.remove('dark');
    } else {
        // For 'dark', we don't technically need a class since it's root, 
        // but for consistency/overrides we add it if needed, or rely on root.
        // We add 'dark' for Tailwind's dark mode selector.
        if (theme !== 'dark') {
            html.classList.add(`theme-${theme}`);
        }
        html.classList.add('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();

      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const y = d.getFullYear();
          const m = String(d.getMonth()+1).padStart(2,'0');
          const dy = String(d.getDate()).padStart(2,'0');
          const dateStr = `${y}-${m}-${dy}`;

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      weeklyStats,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      dataYear: new Date().getFullYear(),
      userName: userSettings?.userName || '',
      motto: userSettings?.motto || '',
      isAdmin: userSettings?.isAdmin || false,
      alertTimes: userSettings?.alertTimes || null,
      isRanked: userSettings?.isRanked !== undefined ? userSettings?.isRanked : true,
      isActive: userSettings?.isActive !== undefined ? userSettings?.isActive : true,
      deleteTime: userSettings?.deleteTime || null,
      dayStreak: userSettings?.dayStreak || 0,
      timeZone: userSettings?.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      streakNotification,
      dismissStreakNotification,
      addHabit, 
      toggleHabit, 
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      commitUserOnboarding, 
      setTheme, 
      updateProfile: updateProfileAction,
      resetData, 
      exportData, 
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const y = d.getFullYear();
                 const m = String(d.getMonth()+1).padStart(2,'0');
                 const dy = String(d.getDate()).padStart(2,'0');
                 const ds = `${y}-${m}-${dy}`;

                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DEFAULT_SUGGESTIONS } from '../types';
import { Button } from '../components/Button';
import { X, ChevronLeft, Eye, EyeOff, CheckCircle2, TrendingUp, Check } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { auth } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';
import { checkUserHasHabits } from '../lib/firestore';

type Step = 'intro0' | 'intro1' | 'auth' | 'selection';

export const Onboarding: React.FC = () => {
  const { commitUserOnboarding } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<Step>('intro0');

  // Selection State
  const [selected, setSelected] = useState<string[]>([]);
  const [customHabit, setCustomHabit] = useState('');

  // Auth state
  const [isSignUp, setIsSignUp] = useState(false);
  const [isForgotPassword, setIsForgotPassword] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState('');
  const [resetMessage, setResetMessage] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const toggleSelection = (habit: string) => {
    if (selected.includes(habit)) {
      setSelected(prev => prev.filter(h => h !== habit));
    } else {
      setSelected(prev => [...prev, habit]);
    }
  };

  const addCustom = () => {
    if (!customHabit.trim()) return;
    setSelected(prev => [...prev, customHabit.trim()]);
    setCustomHabit('');
  };

  const finishSelection = async () => {
      if (selected.length === 0) return;
      setIsLoading(true);
      try {
          // Atomic commit of all selected habits and user status
          await commitUserOnboarding(selected);
          navigate('/today');
      } catch (error: any) {
          console.error(error);
          alert('Failed to complete onboarding: ' + error.message);
          setIsLoading(false);
      }
  };

  const handlePasswordReset = async () => {
    setAuthError('');
    setResetMessage('');
    if (!email) {
        setAuthError('Please enter your email address.');
        return;
    }

    setIsLoading(true);
    try {
        await sendPasswordResetEmail(auth, email);
        setResetMessage('Password reset email sent! Check your inbox.');
    } catch (error: any) {
        setAuthError(error.message);
    } finally {
        setIsLoading(false);
    }
  };

  const handleAuth = async () => {
    setAuthError('');
    if (!email || !password) {
        setAuthError('Please enter both email and password.');
        return;
    }

    setIsLoading(true);

    try {
        let cred;
        if (isSignUp) {
            cred = await createUserWithEmailAndPassword(auth, email, password);
            setIsLoading(false);
            setStep('selection');
        } else {
            cred = await signInWithEmailAndPassword(auth, email, password);
            // Check directly against Firestore using the UID from credentials
            // This avoids waiting for the AppContext listener to update
            const hasHabits = await checkUserHasHabits(cred.user.uid);

            if (hasHabits) {
                navigate('/today');
            } else {
                setIsLoading(false);
                setStep('selection');
            }
        }
    } catch (error: any) {
        setAuthError(error.message);
        setIsLoading(false);
    }
  };

  // --- VIEWS ---

  if (step === 'intro0') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col relative overflow-hidden">
              {/* Abstract background grid */}
              <div className="absolute inset-0 pointer-events-none opacity-[0.03] dark:opacity-[0.05]"
                   style={{
                       backgroundImage: 'linear-gradient(currentColor 1px, transparent 1px), linear-gradient(90deg, currentColor 1px, transparent 1px)',
                       backgroundSize: '32px 32px'
                   }}
              />

              <div className="flex-1 flex flex-col items-center justify-center px-6 z-10 animate-fade-in text-ledger-text dark:text-ledger-textDark">

                  {/* Visual: A mock habit card representing the 'Log' */}
                  <div className="w-full max-w-[260px] bg-white dark:bg-ledger-surfaceDark rounded-2xl border border-ledger-border dark:border-ledger-borderDark shadow-2xl mb-12 transform -rotate-3 relative overflow-hidden group">
                       <div className="absolute top-0 left-0 right-0 h-1.5 bg-ledger-accent/20" />
                       <div className="p-5 flex items-center justify-between border-b border-gray-50 dark:border-gray-800">
                          <div className="flex flex-col gap-2">
                              <div className="h-2 w-12 bg-ledger-muted/20 rounded-full" />
                              <div className="h-4 w-28 bg-ledger-text dark:bg-ledger-textDark rounded-sm opacity-90" />
                          </div>
                          <div className="w-10 h-10 bg-ledger-accent rounded-xl flex items-center justify-center text-white shadow-lg shadow-ledger-accent/20">
                              <Check size={20} strokeWidth={4} />
                          </div>
                       </div>
                       <div className="p-5 space-y-4 opacity-40 bg-gray-50/50 dark:bg-white/[0.02]">
                          <div className="flex items-center justify-between">
                              <div className="h-3 w-20 bg-ledger-muted/50 rounded-sm" />
                              <div className="w-8 h-8 rounded-lg border-2 border-dashed border-ledger-border dark:border-ledger-borderDark" />
                          </div>
                          <div className="flex items-center justify-between">
                              <div className="h-3 w-24 bg-ledger-muted/50 rounded-sm" />
                              <div className="w-8 h-8 rounded-lg border-2 border-dashed border-ledger-border dark:border-ledger-borderDark" />
                          </div>
                       </div>
                  </div>

                  <h1 className="text-4xl md:text-5xl font-extrabold text-center tracking-tight leading-none mb-6">
                      The log<br/>
                      <span className="text-ledger-muted">does not lie.</span>
                  </h1>

                  <p className="text-center text-ledger-muted text-lg max-w-xs font-medium leading-relaxed">
                      This is a place to record what you do. Not how you feel about it.
                  </p>
              </div>

              <div className="p-8 z-10 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark to-transparent">
                  <Button fullWidth onClick={() => setStep('intro1')}>Continue</Button>
              </div>
          </div>
      );
  }

  if (step === 'intro1') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in relative">
              <div className="flex-1 flex flex-col items-center justify-center">
                  <div className="w-20 h-20 bg-ledger-surface dark:bg-ledger-surfaceDark border border-ledger-border dark:border-ledger-borderDark rounded-3xl flex items-center justify-center mb-8 shadow-xl shadow-black/5 rotate-3">
                      <CheckCircle2 size={40} className="text-ledger-accent" />
                  </div>
                  <h1 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-4 tracking-tight">
                      Accountability,<br/>Simplified.
                  </h1>
                  <p className="text-ledger-muted text-lg max-w-xs leading-relaxed">
                      No bells, no whistles.<br/>Just a serious tool to track what matters daily.
                  </p>
              </div>
              <div className="w-full space-y-4">
                  <Button fullWidth onClick={() => setStep('auth')}>Get Started</Button>
                  <button onClick={() => setStep('intro0')} className="w-full py-2 text-xs font-bold uppercase text-ledger-muted hover:text-ledger-text transition-colors tracking-widest">Back</button>
              </div>
          </div>
      );
  }

  // Auth Step
  if (step === 'auth') {
    if (isForgotPassword) {
        return (
            <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
                <div className="mb-8 mt-2">
                    <button onClick={() => setIsForgotPassword(false)} className="flex items-center text-ledger-muted hover:text-ledger-text">
                        <ChevronLeft size={20} className="mr-1" /> Back
                    </button>
                </div>
                <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">Reset Password</h2>
                <div className="space-y-6 mt-6">
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent" />
                    {authError && <p className="text-red-500 text-sm">{authError}</p>}
                    {resetMessage && <p className="text-green-500 text-sm">{resetMessage}</p>}
                    <Button fullWidth onClick={handlePasswordReset} disabled={isLoading}>{isLoading ? 'Sending...' : 'Send Link'}</Button>
                </div>
            </div>
        );
    }

    return (
      <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
         <div className="mb-8 mt-2">
            <button onClick={() => setStep('intro1')} className="flex items-center text-ledger-muted hover:text-ledger-text">
                <ChevronLeft size={20} className="mr-1" /> Back
            </button>
         </div>

         <div className="flex-1 flex flex-col justify-center">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 tracking-tight">
              {isSignUp ? 'Create Account' : 'Welcome Back'}
            </h2>
            <p className="text-ledger-muted mb-10">Sync your data across devices.</p>

            <div className="space-y-8">
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted mb-2 block tracking-wider">Email</label>
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-lg text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent placeholder-ledger-muted/30" placeholder="you@example.com" />
                </div>
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted mb-2 block tracking-wider">Password</label>
                    <div className="relative">
                        <input type={showPassword ? "text" : "password"} value={password} onChange={e => setPassword(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-lg text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent pr-10 placeholder-ledger-muted/30" placeholder="••••••" onKeyDown={e => e.key === 'Enter' && handleAuth()} />
                        <button onClick={() => setShowPassword(!showPassword)} className="absolute right-0 top-2 text-ledger-muted hover:text-ledger-text transition-colors">
                            {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                        </button>
                    </div>
                </div>

                {!isSignUp && (
                    <div className="flex justify-end">
                        <button onClick={() => setIsForgotPassword(true)} className="text-xs font-medium text-ledger-muted hover:text-ledger-accent transition-colors">Forgot Password?</button>
                    </div>
                )}
            </div>

            {authError && <div className="mt-6 p-3 bg-red-50 dark:bg-red-900/20 text-red-600 rounded-lg text-sm font-medium">{authError}</div>}

            <div className="mt-10 space-y-4">
                <Button fullWidth onClick={handleAuth} disabled={isLoading}>
                    {isLoading ? 'Processing...' : (isSignUp ? 'Sign Up' : 'Log In')}
                </Button>
                <button onClick={() => { setIsSignUp(!isSignUp); setAuthError(''); }} className="w-full text-center text-xs font-bold uppercase text-ledger-muted hover:text-ledger-text transition-colors tracking-widest">
                    {isSignUp ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
                </button>
            </div>
         </div>
      </div>
    );
  }

  // Selection Step
  if (step === 'selection') {
    return (
      <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col max-w-md mx-auto relative animate-fade-in">
        <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 mt-8 tracking-tight">
              Habit Selection
            </h2>
            <p className="text-ledger-muted text-base mb-8">
              Select habits to start your journey.
            </p>

            {selected.length > 0 && (
                <div className="mb-6 space-y-2">
                    {selected.map((item) => (
                        <div key={item} className="flex items-center justify-between p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark animate-fade-in shadow-sm">
                            <span className="font-semibold text-ledger-text dark:text-ledger-textDark">{item}</span>
                            <button onClick={() => toggleSelection(item)} className="text-ledger-muted hover:text-red-500 transition-colors"><X size={18} /></button>
                        </div>
                    ))}
                </div>
            )}

            <div className="flex flex-wrap gap-2.5 mb-8">
                {DEFAULT_SUGGESTIONS.map(suggestion => (
                    <button
                        key={suggestion}
                        onClick={() => toggleSelection(suggestion)}
                        className={`px-5 py-2.5 rounded-full text-sm font-semibold border transition-all ${selected.includes(suggestion) ? 'bg-ledger-accent text-white border-ledger-accent shadow-md' : 'border-ledger-border dark:border-ledger-borderDark text-ledger-text dark:text-ledger-textDark hover:bg-gray-50 dark:hover:bg-white/5'}`}
                    >
                        {suggestion}
                    </button>
                ))}
            </div>

            <div className="flex gap-3 items-end">
                <div className="flex-1">
                     <label className="text-[10px] font-bold uppercase text-ledger-muted mb-1 block">Custom Habit</label>
                     <input 
                        type="text" 
                        value={customHabit}
                        onChange={(e) => setCustomHabit(e.target.value)}
                        placeholder="e.g. Drink Water"
                        className="w-full bg-transparent border-b-2 border-ledger-border dark:border-ledger-borderDark py-2 text-lg font-medium text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent placeholder-ledger-muted/30"
                        onKeyDown={(e) => e.key === 'Enter' && addCustom()}
                        maxLength={17}
                    />
                </div>
                <button onClick={addCustom} disabled={!customHabit} className="mb-2 text-sm font-bold bg-ledger-accent text-white px-4 py-2 rounded-lg hover:opacity-90 disabled:opacity-30 disabled:cursor-not-allowed transition-all">Add</button>
            </div>
        </div>
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark via-ledger-bg dark:via-ledger-bgDark to-transparent pt-12">
            <Button fullWidth onClick={finishSelection} disabled={selected.length === 0 || isLoading}>
                {isLoading ? 'Creating Account...' : 'Complete Setup'}
            </Button>
        </div>
      </div>
    );
  }

  return null;
};
